INSERT INTO `universities` (`id`, `name`, `type`, `location`, `description`, `campus_branches`, `tuition_fees`, `exam`, `requirements`, `enrollment_requirements`, `contact_links`, `created_at`, `updated_at`) VALUES
(16, 'Pamantasan ng Lungsod ng Pasig (PLP)', 'LUC', 'Pasig', 'This university is highly competitive and primarily serves residents of Pasig, providing quality education with a strong emphasis on professional licensure success.', 'Pasig City only', 'As a local university, PLP offers subsidized education for qualified Pasig residents.', 'The entrance exam is held annually between January and March.', 'General GWA: 85%–90%. \nBSIT/BSCS: At least 85% in Math and Science subjects. \nNursing: 85% GWA with no grade lower than 83% in any subject. \nEducation: 85% GWA; students must maintain an 83% average in all major courses. \nEngineering: At least 85% in Math, Science, and English.', 'Original Form 138 (SF9)\nPSA Birth Certificate (original + 2-3 photocopies)\nGood Moral Certificate\nMedical Clearance (Chest X-ray and Physical Exam)\nResidency Proof (Voter\'s Certificate of the parent or Barangay Residency Permit)', 'Website: www.plpasig.edu.ph\nEmail: admission@plp.edu.ph\nTel: (02) 8643-2070', '2026-05-03 07:59:48', '2026-05-03 14:50:35'),
(17, 'Rizal Technological University (RTU) - Pasig Branch', 'SUC', 'Pasig', 'The RTU Pasig Branch specializes in technology, architecture, and human kinetics, providing state-funded education to students in the Maybunga area.', 'Mandaluyong (Main Campus)', 'State-funded education', 'Their batch-based exams take place from April to May annually.', 'General GWA: 85%\nBSIT/Engineering: At least 85% in Math, Science, and English. \nArchitecture: Includes a specialized drawing/aptitude test.', '• Original Form 138 (SF9)\n• PSA Birth Certificate\n• Good Moral Certificate\n• Medical Clearance\n• 2x2 colored ID with a BLUE background', 'Website: www.rtu.edu.ph\nEmail: admissions@rtu.edu.ph \n', '2026-05-03 08:13:20', '2026-05-03 08:17:19'),
(18, 'University of Asia & the Pacific (UA&P)', 'Private', 'Pasig', 'UA&P is known for its liberal arts foundation and professional specialization in business and technology.', 'Only in Pasig City', 'Private institution rates apply.', 'March annually', 'General GWA: 85%–90%. \nBSIT / Data Science: Competitive ranking based on entrance exam scores.', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance. ', 'Website: www.uap.asia\nEmail: admissions@uap.asia\nTel: (02) 8637-0912', '2026-05-03 08:19:06', '2026-05-03 08:54:30'),
(19, 'Arellano University (Pasig)', 'Private', 'Pasig', 'Arellano Pasig offers an \"Open Admission\" policy with a focus on practical and professional degrees.', 'Manila, Pasay, Malabon, and Mandaluyong', 'Private institution rates apply.', 'Usually conducted on the day of application or via a scheduled walk-in. ', 'Open Admission (Placement Exam).', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance.', 'Website: www.arellano.edu.ph\nEmail: info@arellano.edu.ph ', '2026-05-03 08:55:30', '2026-05-03 08:59:27'),
(20, 'Pasig Catholic College (PCC)', 'Private', 'Pasig', 'PCC is a private Catholic institution providing values-based education in the heart of Pasig.', 'Only in Pasig City', 'Private institution rates apply. \n', 'Entrance exam is every March with an application fee of ₱300.', 'To have a GWA of 80%', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance. \n', 'Website: pasigcatholic.edu.ph\nEmail: registrar@pcc.edu.ph\n', '2026-05-03 08:59:57', '2026-05-03 09:02:45'),
(21, 'Rizal Technological University (RTU) - Main', 'SUC', 'Mandaluyong', 'The main campus of Rizal Technological University is a hub for engineering, sciences, and teacher education.', 'Pasig City', 'State-funded education. ', 'Batch-based every April to May. ', 'General GWA: 80%–85%.\nBSIT/Engineering/Architecture: 85% GWA.\nSpecific Subjects: At least 85% in Math, Science, and English for IT/Engineering; specialized drawing test for Architecture.', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance. ', 'Website: www.rtu.edu.ph\nEmail: admissions@rtu.edu.ph \n', '2026-05-03 09:04:46', '2026-05-03 09:08:02'),
(22, 'Jose Rizal University (JRU)', 'Private', 'Mandaluyong', 'JRU operates on a rolling admission basis, prioritizing accessibility and immediate feedback for applicants.', 'Only in Mandaluyong City', 'Private institution rates apply. ', 'There is no entrance exam for incoming college freshmen or senior high school students.', 'Open Admission (Retention applies).\n', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance, Registration via AdHub.', 'Website: www.jru.edu\nEmail: admission@jru.edu\nTel: (02) 8531-8031 ', '2026-05-03 09:09:14', '2026-05-03 09:13:59'),
(23, 'Don Bosco Technical College (DBTC)', 'Private', 'Mandaluyong', 'DBTC is a premier technical institution known for its \"Interview-First\" approach to selecting students for its specialized labs and workshops.', 'Makati', 'Private institution rates apply. ', 'Interview-Integrated approach after requirement upload.\n', 'To have a GWA of 80%.', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance.', 'Website: www.dbtc.edu.ph\nEmail: registrar@dbtc.edu.ph \n', '2026-05-03 09:14:45', '2026-05-03 09:17:21'),
(24, 'Polytechnic University of the Philippines (PUP) - San Juan', 'SUC', 'San Juan', 'The PUP San Juan branch offers highly sought-after degrees in technology and business under the Polytechnic University of the Philippines system.', 'Manila, Quezon City, Taguig, Parañaque, and Caloocan', 'State-funded education. ', 'Entrance exam occur every April.', 'General GWA: 82% (No grade below 82% for IT). Accountancy: 85% GWA and must pass a departmental qualifying exam.', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance, Registration via iApply. ', 'Website: www.pup.edu.ph\nEmail: sanjuan@pup.edu.ph \n', '2026-05-03 09:18:51', '2026-05-03 09:21:54'),
(25, 'Dominican College', 'Private', 'San Juan', 'Dominican College is a private institution in San Juan with a specialized focus on health sciences and education.', 'Manila', 'Private institution rates apply. ', 'Entrance exam is scheduled per batch.', '80% GWA (85% for Nursing). Nursing Special Requirement: Requires letters of recommendation.\n', 'Original Form 138 (SF9), PSA Birth Certificate, Good Moral Certificate, Medical Clearance. ', 'Website: www.dominican.edu.ph\nEmail: admission@dominican.edu.ph ', '2026-05-03 09:23:26', '2026-05-03 09:25:06'),
(27, 'University of the East – Caloocan', 'Private', 'Caloocan', 'A well-established private university known for strong programs in engineering, business, and arts. Part of the UE system with modern facilities.', 'UE Manila (Main Campus)\nUERMMMMC (Quezon City)', '₱50,000 – ₱80,000 per semester', 'Entrance exam required. Bring required documents on exam day.', 'Entrance exam\nForm 138\nGood Moral Certificate\nPSA Birth Certificate', NULL, '(632) 8367-4572 loc 157\n8364-2472\nstudentaccounts.cal@ue.edu.ph\nfinance@ue.edu.ph', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(28, 'Manila Central University', 'Private', 'Caloocan', 'A comprehensive private university known for strong medical, health sciences, and business programs.', 'None', '₱30,000 – ₱120,000 per semester', 'Entrance exam required for admission.', 'Entrance exam\nForm 138\nGood Moral Certificate\nPSA Birth Certificate', NULL, '(+632) 8364-1071\nhello@mcu.edu.ph', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(29, 'World Citi Colleges', 'Private', 'Caloocan', 'A specialized institution known for aviation, technology, and hospitality-related programs.', 'Quezon City\nAntipolo\nGuimba\nPangasinan', '~₱50,000 per year', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nGood Moral Certificate', NULL, '+63 75 633 9351\nwccatcregistrarbin@wccaviation.com.ph', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(30, 'AMA Computer College - Caloocan', 'Private', 'Caloocan', 'A technology-focused institution offering affordable IT and business programs.', 'Multiple campuses nationwide', '₱20,000 – ₱35,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nGood Moral Certificate', '', '(02) 8363-9008\nama_caloocan@amaes.edu.ph', '2026-05-03 17:04:44', '2026-05-03 17:49:49'),
(31, 'STI College Caloocan', 'Private', 'Caloocan', 'A popular private college known for industry-based programs in IT, business, and hospitality.', 'Multiple campuses nationwide', '₱25,000 – ₱35,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nGood Moral Certificate', NULL, '8294-4001 / 8294-4002', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(32, 'St. Clare College of Caloocan', 'Private', 'Caloocan', 'An affordable private college offering accessible degree programs.', 'None', '₱10,000 – ₱20,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nGood Moral Certificate', NULL, '+63 282324483\nstclarecollege.ph@gmail.com', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(33, 'University of Caloocan City', 'LUC', 'Caloocan', 'A public university offering free education to qualified residents. Prioritizes Caloocan City residents.', 'North Campus\nSouth Campus', 'FREE', 'UCC Admission Test (UCCAT). Apply through the UCC admission portal (AIMS system) before the exam.', 'Senior High School Card (Form 138)\nGrade 11/12 records\nProof of residency (Caloocan students prioritized)\nGood Moral Certificate', '1. Online Application – Register in UCC admission portal (AIMS system)\n2. Upload Requirements – Form 138, Grade 11/12 records, proof of residency\n3. Entrance Exam – Take the UCC Admission Test (UCCAT)\n4. Evaluation – Grades and exam result review\n5. Results Release – Check portal for admission status\n6. Enrollment – Submit physical documents, medical requirements may be needed, final registration of subjects', '(02) 8528-4654\nsouthcampusadmin@ucc-caloocan.edu.ph', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(34, 'Polytechnic University of the Philippines – Caloocan', 'SUC', 'Caloocan', 'A state university known for quality and affordable education. Branch of the main PUP Sta. Mesa campus.', 'Main Campus (Sta. Mesa)', 'FREE (minimal fees)', 'PUP College Entrance Test (PUPCET). Apply through PUP iApply system and choose PUP Caloocan as preferred campus. Exam covers Math, English, Science, and Abstract Reasoning.', 'Grade 11 report card (Form 138)\n2x2 ID picture with name tag\nPSA Birth Certificate\nGrade 12 enrollment proof (if currently Grade 12)', '1. Online Application – Apply through PUP iApply system, choose PUP Caloocan Campus\n2. Upload Requirements – Form 138, 2x2 ID picture, PSA Birth Certificate, Grade 12 enrollment proof\n3. Entrance Exam (PUPCET) – Covers Math, English, Science, Abstract Reasoning\n4. Result Checking – Wait for official results on PUP website or email\n5. Enrollment – Submit original documents, fill out enrollment forms, get schedule and section', 'www.pup.edu.ph', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(35, 'San Beda College Alabang', 'Private', 'Muntinlupa', 'A prestigious private institution known for academic excellence. Part of the San Beda system.', 'San Beda Manila', '₱80,000 – ₱150,000 per semester', 'Entrance exam required for admission.', 'Entrance exam\nForm 138', NULL, '(02) 8236-7222', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(36, 'Lyceum of Alabang', 'Private', 'Muntinlupa', 'An affordable private college with strong criminology and business programs.', 'None', '₱25,000 – ₱50,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138', NULL, '(02) 8850-7781', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(37, 'FEU Alabang', 'Private', 'Muntinlupa', 'A modern campus under FEU known for quality business and tech programs.', 'FEU Manila', '₱60,000 – ₱100,000 per semester', 'Entrance exam required for admission.', 'Entrance exam', NULL, '(02) 8842-5358', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(38, 'STI College Alabang', 'Private', 'Muntinlupa', 'A branch of STI offering practical, skills-based programs.', 'Multiple STI campuses', '₱25,000 – ₱35,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138', NULL, '(02) 8850-1145', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(39, 'Pamantasan ng Lungsod ng Muntinlupa', 'LUC', 'Muntinlupa', 'A local government-funded university offering free education for Muntinlupa residents.', 'None', 'FREE', 'PLMun College Admission Test (PCAT). Apply through the PLMun Admission Portal. Exam covers Math, English, Science, and General Knowledge.', 'Senior High School report card (Form 138)\nCertificate of Good Moral Character\nPSA Birth Certificate\n2x2 ID pictures\nProof of residency', '1. Online Application – Fill out PLMun Admission Portal form, create applicant account\n2. Submit Requirements – Form 138, Good Moral Certificate, PSA Birth Certificate, 2x2 ID pictures, proof of residency\n3. Entrance Exam (PCAT) – Covers Math, English, Science, General Knowledge\n4. Interview/Evaluation – Some courses may require interview or screening\n5. Result Checking – Check via portal or announcement\n6. Enrollment – Proceed to enrollment and sectioning if qualified', '(02) 8862-5960', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(40, 'Colegio de Muntinlupa', 'LUC', 'Muntinlupa', 'A public college providing accessible and tuition-free education primarily for Muntinlupa residents.', 'None', 'FREE', 'CDM Admission Test (CDMAT). Required for all engineering applicants. Register via CDM admission portal.', 'Grade 12 report card\nPSA Birth Certificate\nBarangay Clearance / Residency proof\nMedical clearance and lab tests', '1. Online Application – Register via CDM admission portal\n2. CDMAT (Entrance Exam) – Required for all engineering applicants\n3. Pre-Enrollment Stage – Fill out questionnaire/interview form, submit documents\n4. Submission of Requirements – Grade 12 report card, PSA Birth Certificate, Barangay Clearance, Medical clearance\n5. Evaluation – Grades and documents are checked\n6. Final Enrollment – Submit final documents, choose schedule/section', '(02) 8861-7464', '2026-05-03 17:04:44', '2026-05-03 17:04:44'),
(41, 'Taguig City University', 'LUC', 'Taguig', 'A local government-funded institution providing free tertiary education specifically for residents of Taguig. Focuses on fields such as business, education, engineering, and technology.', 'None', 'FREE / fully subsidized under RA 10931 + ₱5,000 stipend per semester for qualified Taguig residents', 'All applicants must undergo an assessment interview prior to the Scholastic Admission Test. Quota programs like Nursing and Engineering require this interview before testing. Exam held April 25–26, 2026.', 'Grade 11 Report Card\nGrade 12 First Semester Report Card\nCertificate of Good Moral Character\nPSA Birth Certificate\nTwo 2x2 ID pictures\nProof of Taguig residency (Barangay certificate)', '1. Online Application (Feb 13 – Mar 20, 2026) – Register via portal.tcu.edu.ph/admission\n2. Interview & Exam (Apr 25–26, 2026) – Assessment interview then Scholastic Admission Test\n3. Enrollment (May–Jun 2026) – Submit: Original Notice of Admission, Original Form 138 (SF9), Original PSA Birth Certificate, Good Moral Certificate, Medical clearance, Residency verification\nTransferees must also submit Honorable Dismissal and Official TOR', 'Gen. Santos Ave., Central Bicutan, Taguig City\nTel: 8635-8300 / Registrar: 8635-8300 (7204) / 0961-887-2644\nEmail: registrar@tcu.edu.ph\nWebsite: tcu.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(42, 'Polytechnic University of the Philippines – Taguig', 'SUC', 'Taguig', 'A state university branch offering affordable quality programs in engineering, business, and applied sciences under the PUP system.', 'Main Campus: Sta. Mesa, Manila\nPUP Parañaque\nPUP Quezon City\nPUP San Juan\nBataan, Bulacan, Laguna, Cavite, Quezon', 'FREE / fully subsidized under RA 10931 + minimal miscellaneous fees only', 'PUP College Entrance Test (PUPCET) held mid to late April. Apply online via PUP iApply. Must be Grade 12 graduating student or SHS graduate with GWA not lower than 82% and no prior college units. For Accountancy, an additional departmental qualifying exam is required after passing PUPCET.', 'Grade 11 Report Card\n2x2 inch colored ID photo with name tag', '1. Online Application (Jan 12 – Mar 31, 2026) – Apply via PUP iApply for PUPCET, choose Taguig campus\n2. Exam (April 2026) – PUPCET; Accountancy requires additional departmental qualifying exam after passing\n3. Enrollment (Jun–Aug 2026) – Submit: Original Form 138, Original PSA Birth Certificate, Good Moral Certificate, Two 2x2 pictures, Medical clearance from PUP clinic, Notice of Admission/Qualified Slip\nTransferees need Honorable Dismissal + TOR\nAccountancy: 85% GWA recommended + additional qualifying exam', 'Gen. Santos Ave., Lower Bicutan, Taguig City\nTel: (02) 837-5858 / (02) 837-5860\nEmail: taguig@pup.edu.ph\nWebsite: pup.edu.ph/taguig', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(43, 'Technological University of the Philippines – Taguig', 'SUC', 'Taguig', 'The premier state technological university in Taguig focusing on engineering and technical-vocational teacher education.', 'Main Campus: Ayala Boulevard, Ermita, Manila\nTUP Cavite (Dasmarinas)\nTUP Visayas (Talisay)\nBatangas extension\nQuezon extension', 'FREE / fully subsidized under RA 10931 + minimal lab fees only', 'TUP Scholastic and Technical Aptitude Test (TUPSTAT) – written + oral interview. Apply online via ERS (ers.tup.edu.ph) during February to March. Exam dates are batch-based and announced on tupt.edu.ph.', 'Photocopy of Grade 11 and Grade 12 cards\nGood Moral Certificate', '1. Online Application (Feb–Mar) – Apply via ers.tup.edu.ph + Google Form\n2. Exam – TUPSTAT (written + oral interview); batch-based dates on tupt.edu.ph\n3. Enrollment (typically Jun–Jul after passing TUPSTAT) – Submit: Original Form 138, PSA Birth Certificate, Good Moral Certificate, Medical clearance, 2 pcs 2x2 pictures\nTransferees: Honorable Dismissal + TOR', 'Km. 14 East Service Road, South Super Highway, Taguig City\nTel: (02) 823-1774\nEmail: taguig@tup.edu.ph\nWebsite: tupt.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(44, 'Enderun Colleges', 'Private', 'Taguig', 'Known for international-caliber programs in hospitality, business, culinary, architecture, and multimedia with global partners. Located at McKinley Hill.', 'None', '₱300,000 – ₱400,000 per semester (local rate, 24 units)', 'Submit an essay and complete an admissions interview as part of the screening process. Application is ongoing for August 2026 intake.', 'Photocopy of Grade 10/11/12 report card\nPSA Birth Certificate\nTwo 2x2 pictures\nTransferees: Certified True Copy of Grades, Certification of Eligibility to Transfer, Honorable Dismissal, Good Moral Certificate (signed by Dean/Guidance/Head of Student Affairs), Copy of Syllabi and Course Descriptions, Formal written Application for Transfer', '1. Apply online (ongoing for August 2026 intake)\n2. Submit essay and complete admissions interview\n3. Submit enrollment documents prior to August 2026', '1100 Campus Avenue, McKinley Hill, Taguig 1634\nTel: (02) 8856-5000\nEmail: admissions@enderuncolleges.com\nWebsite: enderuncolleges.com', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(45, 'STI College – Global City', 'Private', 'Taguig', 'Known for industry-driven IT, business, and hospitality programs with global certifications and career-ready modules. Located in Bonifacio Global City.', 'Multiple STI branches nationwide (Alabang, Bacoor, Dasmariñas, Pasay, etc.)', '₱40,000 – ₱55,000 per semester (approximate)', 'Open admission/evaluation based on documents. Rolling admission until July 2026.', 'Original Form 138 / SF9\nOriginal Form 137 / SF10\nPSA Birth Certificate\nGood Moral Certificate\nTwo 2x2 ID pictures\nTransferees: TOR evaluation required', '1. Apply online at apply.sti.edu (rolling basis until July 2026)\n2. Open admission/evaluation based on documents\n3. Enrollment (May–Jul 2026) – Submit Form 138/SF9, Form 137/SF10, PSA Birth Certificate, Good Moral Certificate, two 2x2 ID pics\nTransferees must undergo TOR evaluation', 'STI Academic Center, University Parkway Drive, Bonifacio Global City, Taguig 1634\nTel: (02) 8551-4984\nEmail: via FB globalcity.sti.edu\nWebsite: sti.edu', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(46, 'Dr. Filemon C. Aguilar Memorial College of Las Piñas', 'LUC', 'Las Piñas', 'A city-supported accessible college for Las Piñas residents only. Scholarship-focused with high-standard business and IT programs. No transferees accepted.', 'None', 'FREE / fully subsidized for qualified Las Piñas residents under RA 10931', 'DFCAMCLP College Admission Test (CET) – batch-based exam held in May 2026. Must score at least 75%. Strictly for Las Piñas residents only; no transferees accepted.', 'Must be a K-12 graduate (ABM preferred)\nLas Piñas resident (proof required)\nGeneral average of at least 83% with NO grade below 80% in Physical Science, Biological Science, Statistics & Probability, General Math, and English\nStrictly first-time locals only; no transferees accepted', '1. Application (Feb–Apr 2026) – Onsite submission of requirements from March to May (8:00 AM–2:00 PM)\n2. Exam (May 2026) – DFCAMCLP College Admission Test; must score at least 75%\n3. Enrollment (May–Jun 2026) – Proceeds after passing CET and residency verification', 'Golden Gate Subd., Talon III / Pamplona 3, Las Piñas City\nTel: (02) 805-8425 / 986-8763\nEmail: dfcaitti.registrar@yahoo.com.ph\nWebsite: dfcamclp.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(47, 'Centro Escolar Las Piñas', 'Private', 'Las Piñas', 'Known for empowering students with Science and Virtue. No entrance exam required, flexible enrollment with low downpayment options and accessible quality programs.', 'Manila (Main/Mendiola)\nMakati (Gil Puyat and Legazpi)\nMalolos\nCebu City', '₱19,989 – ₱40,000 per semester (approximate; downpayment as low as ₱2,000–₱5,000 with installments)', 'No entrance exam required. Apply directly from January to May 2026.', 'Grade 12 Original Report Card (SF-9 or F138)\nPhotocopy of PSA Birth Certificate\n2x2 ID Picture (2 copies)\nOriginal Certificate of Good Moral Character\nRegistration Fee of ₱300.00\nOne Long Brown Envelope\nTransferees: TOR/Copy of Grades, PSA Birth Certificate, 2x2 ID pictures, Good Moral Certificate, Transfer Credentials/Honorable Dismissal, Drug Test Result, Registration Fee ₱300, Long Brown Envelope', '1. Apply directly with no entrance exam (Jan–May 2026)\n2. Submit enrollment requirements', 'Dr. Faustino Uy Ave., Pilar Village, Almanza Uno, Las Piñas City\nTel: (02) 8801-7211 to 15 / 0927-353-7432\nEmail: celpadmission@celp.edu.ph / registrar@celp.edu.ph\nWebsite: www.celp.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(48, 'STI College Las Piñas', 'Private', 'Las Piñas', 'Known for industry-driven IT, business, and practical skills with flexible enrollment, global certifications, and career-ready modules.', 'STI College Alabang\nSTI College Bacoor\nSTI College Dasmariñas\nSTI College Rosario\nSTI College Pasay-EDSA', '₱40,000 – ₱50,000 per semester (approximate)', 'Open to all with no specific grade requirements. Scholarship applicants must take the SOS Qualifying Exam at the campus. Application period April to May 2026.', 'Original Form 138 / SF9-SHS\nOriginal Form 137 / SF10-SHS\nPSA-issued Birth Certificate\nOriginal Certificate of Good Moral Character\nMedical Certificate of Chest X-ray results\nFor BS Hospitality Management applicants: Medical Certificate of Hepatitis A & B Screening\nTransferees: Certificate of Transfer (Honorable Dismissal), Official TOR, PSA Birth Certificate, Good Moral Certificate, Medical Certificate of Chest X-ray results', '1. Register online or via campus (Apr–May 2026)\n2. Open admission; Scholarship applicants take SOS Qualifying Exam\n3. Submit enrollment documents', 'Alabang-Zapote Road corner V. Guinto Street, Pamplona Tres, Las Piñas City 1740\nTel: (02) 8856-4484 / 8871-9437 / 8871-8327\nWebsite: www.sti.edu', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(49, 'AMA Computer College Las Piñas', 'Private', 'Las Piñas', 'Known for innovative U-Learn model, industry-aligned IT/engineering/business programs, real-world focus, and frequent 45% discounts.', 'AMA Caloocan\nAMA Fairview Quezon City\nAMA Mandaluyong\nAMA Makati\nAMA Manila\nAMA Parañaque\nAMA Pasig\nAMA Quezon City (Main)', '₱25,000 – ₱45,000 per semester (approximate; 45% tuition/lab discounts common)', 'Open admission/evaluation. Rolling admissions with no competitive entrance exam.', 'Accomplished Online Application Form\nHigh School Report Card (Form 138)\nPSA Birth Certificate (Photocopy)\nCertificate of Good Moral Character\n2x2 ID Photo\nTransferees: Online Application Form, Official TOR, Honorable Dismissal/Transfer Credentials, Good Moral Certificate, PSA Birth Certificate (Original), 2x2 ID Photo', '1. Submit online application (Rolling Admissions)\n2. Open admission/evaluation\n3. Submit enrollment documents', 'AC & Sons Bldg., Zapote Alabang Road, Almanza I, Las Piñas City\nTel: (02) 8656-0654 / 0960-333-6076 / 0928-335-6732\nEmail: ama_university@amaes.edu.ph\nWebsite: www.amaes.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(50, 'ABE International College of Business and Economics – Las Piñas', 'Private', 'Las Piñas', 'Known for affordable business-focused education with strong programs in management, hospitality, tourism, and accountancy. Part of the AMA Education System network.', 'ABE Manila\nABE Fairview\nABE Cubao\nABE Makati', '₱20,000 – ₱40,000 per semester (approximate; common 45% discounts on tuition/lab fees)', 'No highly competitive entrance exam. Admission relies on pre-registration and document assessment. Qualifying Exams usually held every Friday or Saturday from March to May.', 'Report Card (Form 138)\nCertificate of Good Moral Character\nTwo pcs 1x1 and 2x2 pictures with red background\nTransferees: Transcript of records or true copies of grades, Honorable Dismissal, Good Moral Certificate, Letter of Application, Letter of Parental Consent, Two pcs 1x1 and 2x2 pictures with red background', '1. Pre-registration via AMAES/ABE online portal to get applicant reference number\n2. Submit initial documents for evaluation\n3. Qualifying Exam (Fri or Sat, Mar–May)\n4. Interview (1–2 weeks after passing exam or submitting requirements)\nApplication Period: January 2026 to May 30, 2026', '165 Real St., Alabang-Zapote Road, Pamplona Uno, Las Piñas City\nTel: 0935 320 2931 / 0954 235 3920\nEmail: abe_laspinas@amaes.edu.ph\nWebsite: abe.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(51, 'Pacific Intercontinental College', 'Private', 'Las Piñas', 'Known for flexible transnational/distance learning offering bachelor to doctoral programs in business and education.', 'None', '₱12,000 – ₱25,000 per semester (approximate)', 'No traditional campus-based entrance exam. Admission is based on evaluation of submitted academic credentials. PIC operates on three academic terms per year (January, May, September).', 'Freshmen: High school graduate (Grade 12), 5 Passport-sized Photos, Copy of Government-issued Photo ID, Final School Transcript of Records (TOR), Certificate of Graduation/High School Diploma\nTransferees: Completion of at least 60 academic credits from accredited institution, TOR with remarks \"For further studies\", Honorable Dismissal/Transfer Credentials', '1. Fill out Online Application Form via PIC portal or email completed form to pic1@pic.edu.ph\n2. Document Verification – Admissions Office verifies eligibility\n3. Tuition Fee Payment – Bank deposit or Credit/Debit card via PayPal\n4. Official Registration – Student ID Number and Virtual Classroom access granted within 48 hours of payment\nTerms: January (deadline Dec 15), May (deadline Apr 15), September (deadline Aug 15)', 'Lot 20 Blk. 30, Silver Cor., Marble Road, Pilar Village, Las Piñas City 1750\nTel: (02) 872-0773 / 478-7710 / 0917-570-5039\nEmail: pic1@pic.edu.ph\nWebsite: www.pic.edu.ph', '2026-05-03 17:48:40', '2026-05-03 17:48:40'),
(52, 'University of Makati', 'LUC', 'Makati', 'A top-tier local university in Makati City widely recognized for its Dual Training System, combining classroom lessons with actual hands-on training in real industries to produce industry-ready graduates.', 'Single main campus at J.P. Rizal Extension, West Rembo, Makati City', 'Automatic Scholarship: All incoming undergraduate students are granted 100% tuition-free for their first semester.\nToken Fee by GWA:\n1.00–1.49: Exempt (₱0)\n1.50–1.74: ₱1,000 per semester\n1.75–2.24: ₱3,000 per semester\n2.25–2.74: ₱5,000 per semester\n2.75–3.00: Full Tuition ₱2,000 per unit', 'College Entrance Test covers English, Math, and Science. Online registration opens in February. Some institutes (Nursing, Psychology) require a face-to-face interview. Admission is limited to top-performing applicants.', 'For Makati Residents: GWA of at least 85% (some programs require 90%+)\nFor Non-Makati Residents: GWA of 90% or better\nPSA Birth Certificate (original and photocopy)\nRecent 2x2 ID Pictures (2 copies, white background)\nReport Card (Form 138)\nMakati Voter\'s Certificate (own if 18+, parent/sibling if below 18)', 'Step 1: Download and email Disclosure of Medical Condition and Residency Verification Form (if applicable)\nStep 2: Submit in long plastic envelope to Registrar: Original Notice of Admission, Form 137-A, Grade 12 Report Card, Good Moral Certificate, NCAE Results, PSA Birth Certificate photocopy, 1 long white folder, 2x2 ID picture\nStep 3: Log in to umak.edu.ph/olea, select NSTP and Block Section, save schedule\nStep 4: Apply for exemption or pay via GCash/iBayad (min. downpayment ₱500 residents / ₱1,500 non-residents)\nStep 5: Certificate of Registration (COR) emailed within 24–72 hours', 'J.P. Rizal Ext., West Rembo, Makati City 1215\nEmail: info@umak.edu.ph\nRegistrar: (02) 8882-0675 | registrar@umak.edu.ph\nAdmissions: (02) 8883-1860 | 0945-648-2352 | cas@umak.edu.ph\nPresident: (02) 8882-0679 | president@umak.edu.ph\nWebsite: umak.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(53, 'AMA Computer College – Makati', 'Private', 'Makati', 'A private institution and member of the AMA Education System (AMAES), the largest IT education network in Asia. Specializes in technology-driven degrees and industry-certified training.', 'AMA University Quezon City (Main)\nAMA Fairview\nAMA Manila\nAMA Caloocan\nAMA Las Piñas\nAMA Parañaque\nAMA Pasig', '₱25,000 – ₱40,000 per semester\nDown payment: ₱2,500 – ₱3,000\n45% Discount available during anniversary promotions for new and returning students enrolling minimum 18 units', 'Open Admission policy. No traditional competitive entrance exam. Students undergo a placement interview and assessment to determine the best starting point for their chosen course. Admissions are ongoing year-round due to Trimester system.', 'Online Inquiry: Fill out AMA Online Inquiry Form\nGrade 10 Report Card (Form 138)\nInterview/Guidance with admissions officer', 'Original Form 138 (Report Card)\n2x2 ID Pictures (white background)\nEnrollment Fee/Downpayment', '5486 South Superhighway cor. Gen. Tinio St., Bangkal, Makati City\nMobile: 0961-242-2507 / 0928-335-6732\nLandline: (02) 8893-7325 / 8893-7366\nEmail: amacc.makati@amaes.edu.ph\nWebsite: www.ama.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(54, 'AMA School of Medicine', 'Private', 'Makati', 'The medical school of the AMA Education System known for its integrated curriculum combining basic and clinical sciences, designed to produce self-directed and lifelong learners.', 'AMASOM Cavite\nAMASOMS Baguio', '~₱300,000 for the first year\n~₱200,000 for the second year', 'Applicants must have a valid NMAT score taken within the last two years. Minimum required percentile is 40th percentile consistent with CHED standards.', 'Four-year Bachelor\'s degree in Science or Arts\nPreferred GWA of at least 80%\nOfficial Transcript of Records (TOR)\nDiploma or Certificate of Graduation\nNMAT Official Result\nCertificate of Eligibility from CHED', '1. Fill out formal Application for Admission at AMASOM Admissions Office\n2. Attend personal interview with the Dean or College Secretary\n3. Submit all original required documents in a long brown envelope\n4. Have fees assessed by the accounting section\n5. Pay required tuition and miscellaneous fees to the cashier', '8th Floor, AMA College Makati, 5486 South Superhighway cor. Gen. Mojica St., Bangkal, Makati City\nMobile: 0951-188-0999 / 0928-335-6732\nEmail: asm_makati@amaes.edu.ph / info@amaschoolofmedicine.org.ph\nWebsite: amaschoolofmedicine.amaes.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(55, 'Asian Institute of Management', 'Private', 'Makati', 'A private non-profit graduate school famous for producing Global Leaders and CEOs. Offers a Double-Degree Program in partnership with the University of Houston for undergraduates.', 'Main and only campus in Makati. Undergraduate program includes an international pathway with option to take 4th year at University of Houston, USA.', 'Approximately ₱450,000 – ₱550,000 per year', 'AIM uses NMAT by GMAC or similar aptitude assessment. No traditional pass/fail multiple-choice exam. For August 2026 intake, application deadline is May 31, 2026.', '2-Minute Video Essay explaining why you want to join the program\nPersonal Statement (500–650 words)\nSenior High School Records (proof of graduation or current Grade 12 enrollment)', 'Official Transcript of Records (Form 137)\nPSA Birth Certificate\nReservation Fee: ~₱50,000 (to secure slot, deductible from tuition)\nValid Passport (required early due to US-based degree component)', '123 Paseo de Roxas, Makati City\nLandline: +63 2 8892 4011 to 25\nEmail: bsdsba@aim.edu\nWebsite: aim.edu', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(56, 'Asian Institute for Distance Education', 'Private', 'Makati', 'A private non-sectarian school founded in 1984, famous for being one of the first CHED-accredited distance learning institutions in the country. Students study using self-paced modules.', 'Main and only campus in Makati. Distance education allows study from anywhere.', '₱15,000 – ₱25,000 per semester (depending on number of subjects)', 'Open Admission policy. No competitive entrance exam. Basic orientation or interview to ensure readiness for independent study.', 'High School Report Card (Form 138) – Original\nPSA Birth Certificate (original and photocopy)\n2x2 ID Pictures (2 pieces, white background)\nMarriage Contract (for married female applicants only)', '1. Fill out application form on AIDE website\n2. Send original documents to Makati office (walk-in or LBC/Grab)\n3. Pay initial fee via bank deposit or digital payment (GCash/Maya)\n4. Receive learning modules (physical or digital) after enrollment', 'Unit 302 Greenbelt Mansion, 106 Perea St., Legaspi Village, 1229 Makati City\nLandline: (02) 8810-0968\nMobile: (02) 8277-0169 / (02) 8813-0565 / 09063871254 (Globe) / 09076450361 (Smart)\nEmail: aide_foun@yahoo.com / Aidemakati@gmail.com\nWebsite: www.aide.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(57, 'Asia Pacific College', 'Private', 'Makati', 'A private non-profit institution recognized as a Center of Excellence in IT Education. Famous for its I-ACE Program where students spend their entire senior year working full-time in a real company. Part of the National University (NU) system.', 'Main and only campus in Makati (also referred to as NU APC)', '₱35,000 – ₱45,000 per term (Trimester system)\nAnnual total: ~₱105,000 – ₱135,000\nSM Foundation Scholarship available (full tuition + allowance)', 'Entrance exam evaluates logic, English proficiency, and mathematical ability. For August 2026 intake, testing starts January 2026 through July 2026. Book online via RamConnect portal.', 'Grade 11 & 12 Report Cards\nOnline Application via RamConnect\nApplication Fee: ₱500', 'Original Grade 12 Report Card (Form 138)\nOriginal PSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID Photos (white background)', '3 Humabon Place, Magallanes, Makati City 1232\nAdmissions Email: admissions@apc.edu.ph\nTelephone: 8852-9232 (Locals: 186, 201, 203, 204)\nMobile: 0917-816-5570 / 0933-816-4227 / 0917-546-7192\nWebsite: www.apc.edu.ph\nRegistrar: registrar@apc.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(58, 'Assumption College', 'Private', 'Makati', 'A private Catholic women\'s college in Makati. Famous for Assumption Education which focuses on making women strong, socially responsible leaders and creative thinkers.', 'Assumption Lorenzo Drive Makati\nAssumption San Lorenzo Village Makati', '₱140,000 – ₱180,000 per year (depending on course and units)\nAcademic Scholarship for Top 10 of HS batch\n5% cash discount for full year payment upon enrollment', 'Assumption College Admission Test (ACAT) measures logic, verbal, and math skills. Exams held November to June. Must book slot online after paying testing fee (~₱500–₱600).', 'Minimum GPA of 85% from Grade 11 and 12\nRecommendation Forms (one from SHS Principal, one from Guidance Counselor)\nOnline Application via AC Admissions Hub', 'Original Grade 12 Report Card (Form 138)\nOriginal PSA Birth Certificate\nPhotocopy of Senior High School Diploma\nMedical Clearance including physical exam and chest X-ray from school-approved clinic', 'Landline: (02) 8817-0757 (Admissions: Loc. 2050)\nMobile/Viber: 0917-186-0855\nEmail: admissions@assumption.edu.ph\nWebsite: www.assumption.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(59, 'CAP College Foundation', 'Private', 'Makati', 'A private non-profit school known as \"The Distance Learning Alternative System.\" Founded in 1988, follows the Open University model with self-paced modules. Fully CHED-accredited.', 'Luzon: Baguio, San Fernando (La Union), Tuguegarao, Batangas City, Imus (Cavite), Sta. Cruz (Laguna)\r\nVisayas: Cebu City, Iloilo City, Tagbilaran (Bohol), Dumaguete\r\nMindanao: Davao City, Cagayan de Oro, General Santos, Butuan, Puerto Princesa', '~₱1,000 per unit\r\n~₱3,000 per 3-unit subject (inclusive of modules)\r\nInstallment plans available; pay per subject rather than full semester', 'Open Admission policy. No competitive entrance exam. Apply and start studies at any time of the year.', 'For Freshmen: Original High School Report Card (Form 138)\r\nPSA Birth Certificate\r\n2x2 and 1x1 ID pictures (white background)\r\nTemporary Enrollment Waiver available if original records are not yet ready', 'Submit documents, pay initial fee, and receive modules after confirmation of enrollment.', '126 Amorsolo cor. V.A. Rufino Sts., Legaspi Village, Makati City\r\nLandline: (02) 8812-6923 / (02) 7501-9394\r\nEmail: registrar@capcollege.com.ph\r\nWebsite: elearning.capcollege.com.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(60, 'Centro Escolar University – Makati', 'Private', 'Makati', 'A high-quality private university in Makati CBD known for its Science and Virtue philosophy. Operates two campuses: Gil Puyat Campus (science and law) and Legaspi Village Campus (business, arts, and dentistry).', 'CEU Manila\nCEU Malolos\nCEU Cebu\nCEU Las Piñas', 'Health & Science Programs: ₱61,000 – ₱83,000 per semester\nBusiness, Accountancy & Technology: ₱51,000 – ₱63,000 per semester\nHospitality & Tourism Management: ₱53,000 – ₱65,000 per semester\nEducation, Liberal Arts & Social Work: ₱45,000 – ₱52,000 per semester\n2% discount for full payment upon enrollment\n5% additional discount for early enrollment', 'Testing began August 2025 and continues through July 14, 2026. Register and schedule exam via Official Online Admissions Portal. On-campus testing: ₱550. Online examination: ₱850.', 'Accomplished Application Form via CEU Admissions Portal\nApplication/Testing Fee (₱550 on-campus or ₱850 online)\nLatest Grade 12 Report Card\nRecent 2x2 ID Photo', 'Notice of Admission\nOriginal Grade 12 Report Card (Form 138)\nPermanent School Record (Form 137) – Original with school seal\nPSA Birth Certificate – Original\nCertificate of Good Moral Character – Original\n4 copies of 1.5x1.5 or 2x2 ID photos', '259 Senator Gil Puyat Ave., Makati City\nPhone: (02) 8889-8169 / 8889-7493 / 8843-0300\nAdmissions Email: ceumakatiadmission@ceu.edu.ph\nWebsite: www.ceu.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(61, 'Global City Innovative College', 'Private', 'Makati', 'A private non-sectarian college founded in 2002, known as \"The Yellow Building.\" Built with the vision of providing world-class professional training in a business-centric environment.', 'None', '₱30,000 – ₱45,000 per semester\n5–10% full payment discount\nAcademic Scholarship for students who graduated with high honors in SHS', 'Basic assessment exam covering English, Math, and Abstract Reasoning. Used for placement rather than strict elimination. Exams begin February 2026 through July 2026 for August 2026 intake.', 'Photocopy of Grade 12 Report Card\n2x2 ID Picture (white background)\nApplication Fee (~₱300–₱500)', 'Original Grade 12 Report Card (Form 138)\nOriginal PSA Birth Certificate\nCertificate of Good Moral Character\nMedical Certificate (required for MedTech and Hospitality students)', '444 EDSA, PET Plans Tower Annex, Makati City (near Guadalupe)\nLandline: (02) 8812-4242 / (02) 7757-5588\nMobile: 0917-535-9490\nEmail: admission@global.edu.ph\nWebsite: www.global.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(62, 'Far Eastern University – Makati', 'Private', 'Makati', 'A high-tech private school and professional satellite campus of FEU Manila. Located in the Makati Business District, famous for Business, Accountancy, and IT programs and Board Exam Topnotchers.', 'FEU Manila (Main)\nFEU Institute of Technology\nFEU Diliman\nFEU Cavite\nFEU Alabang\nFEU Roosevelt\nFEU-NRMF', 'Basic Tuition: ~₱2,056 per unit\nFor 20-unit load: ~₱41,120\nMiscellaneous Fees: ~₱13,494 per semester\nFEUCAT exam fee: ₱500\nAdmission Fee: ₱828 (local)\n5% discount for full cash payment by deadline', 'FEU College Admissions Test (FEUCAT) covers English, Mathematics, and Science. Approximately 3 hours. Exams held every Saturday at 8:00 AM or 1:00 PM. Book online through FEU portal after paying ₱500 fee.', 'Proof of Payment (₱500 exam fee)\nAdmissions Form (digital or printed from FEU portal)\nSchool ID (valid, for exam day)', 'Grade 12 Report Card (SF9) – Original\nCertificate of Good Moral Character – Original\nPSA Birth Certificate – Original\nFEUCAT Result (printed from portal)\n2x2 ID Pictures (2–3 pieces, white background, with name tag)\nMedical Certificate (for health-related or specialized courses)', 'FEU Makati, Gil Puyat Avenue cor. Zuellig Loop, Makati City\nTelephone: (02) 8836-2002 / 8836-2033 / 8836-9870 loc. 119\nEmail: admissions@feu.edu.ph / feu-makati@feu.edu.ph\nWebsite: www.feu.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(63, 'iACADEMY', 'Private', 'Makati', 'A private non-sectarian school specializing in courses like Animation and Game Development. Known for its Nexus campus which feels like a modern tech office. IBM Center of Excellence and Toon Boom Center of Excellence.', 'Makati (Main Campus): iACADEMY Nexus, 7434 Yakal St., Makati City\nCebu Campus: iACADEMY Cebu, Cebu IT Park, Lahug, Cebu City', '₱70,000 – ₱100,000 per term (Trimester system)\nAnnual total: ~₱210,000 – ₱300,000\nSibling Discount and Merit Scholarships available', 'iACADEMY College Admissions Test (iCAT) measures logic, abstract reasoning, and English. Admissions for Term 1 (August 2026) are ongoing. Exams held on weekdays and select Saturdays.', '2x2 ID Photo (white background)\nPhotocopy of School ID\nPSA Birth Certificate\nGrade 11 & 12 Report Cards (for evaluation)', 'Original Grade 12 Report Card (Form 138)\nCertificate of Good Moral Character\nTransfer Credentials (for transferees)\nPayment of Tuition/Enrollment Fee', 'Landline: (02) 8889-5555\nEmail: admissions@iacademy.edu.ph\nWebsite: www.iacademy.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(64, 'Loral Douglas Woosley Bethany Colleges', 'Private', 'Makati', 'A private non-profit Christian college focused on building strong character and leadership skills. Well-known for Education and Theology programs, training students to serve their community.', 'Part of the BBCEMFI network including Baptist Bible College and Bethany Baptist Academy, all in Makati.', '₱15,000 – ₱22,000 per semester\nPastoral/Ministry Discount for children of pastors or active church members\nAcademic Scholarship for students who graduated with honors', 'Admission Interview and Basic Assessment rather than a highly competitive exam. Focuses on character and willingness to learn. Assessments ongoing during enrollment months (usually June to August).', 'Original Senior High School Report Card (Form 138)\nPSA Birth Certificate (Original & Photocopy)\nCertificate of Good Moral Character\nRecommendation Letter (from a teacher or Church Pastor)', '1. Visit campus for interview with Dean or Admission Officer\n2. Submit original documents to the Registrar\n3. Pay required registration fee or downpayment\n4. Submit 2x2 ID Pictures (3 pieces, white background)', '1714 Dian Street, Palanan, Makati City\nLandline: (02) 8833-4576 / 8831-4123\nEmail: ldwbc_makati@yahoo.com', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(65, 'Makati Medical Center College', 'Private', 'Makati', 'The educational partner of Makati Medical Center (MakatiMed), one of the top hospitals in the Philippines. A premier school for students who want to become high-quality healthcare professionals.', 'Main & Only Campus: 1061 Metropolitan Avenue, Makati City\nStudents have access to various top-tier hospital affiliations for hands-on training across Metro Manila', '₱60,000 – ₱70,000 per semester\nAnnual total: ~₱120,000 – ₱140,000\nEntrance Scholarships for students who graduated with High Honors', 'Basic exam testing Science, Math, and English knowledge. Admissions for 2026 school year open January through July. Book exam date online through website.', 'Grade 12 Report Card (copy of most recent grades)\nOnline Application via Medici College website\nApplication Fee: ~₱500', 'Original Grade 12 Report Card (Form 138)\nOriginal PSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID Photos (white background)\nMedical Clearance including physical exam and X-ray from clinic', '1061 Metropolitan Avenue, Makati City\nLandline: (02) 8888-8999\nEmail: info@medicicollege.com\nWebsite: www.medicicollege.com', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(66, 'Mapúa University – Makati', 'Private', 'Makati', 'A premier private school in the Makati CBD recognized as a global leader in technology and business education. Uses a Quarterm system and has a partnership with Arizona State University.', 'Mapúa University (Main) – Intramuros\nMapúa Schools of Tourism and Hospitality Management – Parañaque\nMalayan High School of Science – Pandacan, Manila\nMapúa Malayan Colleges Laguna (MCL)\nMapúa Malayan Colleges Mindanao (MCM) – Davao City', 'School of Information Technology: ₱58,000 – ₱63,000 per quarter\nSchool of Business: ₱52,000 – ₱58,000 per quarter\nSchool of Health Sciences: ₱60,000 – ₱70,000 per quarter\nSchool of Media Studies: ₱55,000 – ₱62,000 per quarter\nFully Online Programs: ₱47,000 – ₱55,000 per quarter', 'MPASS (Mapúa Placement and Aptitude for Student Success) exam. Online \"Anytime, Anywhere\" schedule via Cardinal EDGE portal after paying ₱300 application fee. Application window open until July 2026.', 'Online Application: Register and fill out Undergraduate Application Form\nMPASS Fee: ₱300\nReservation Fee after passing MPASS: ₱5,000 (non-refundable)', 'Grade 12 Report Card (Form 138) – Original and photocopy\nPSA Birth Certificate – Original on PSA paper\nCertificate of Good Moral Character – Original with school seal\nPrincipal\'s Certification (Form 137-A still in school file)\nTwo 1.5\"x1.5\" ID photos\nStudent Data Sheet (with ID picture)\nAcademic Honesty Agreement\nUndertaking Against Joining Fraternities/Sororities\nSpecimen Signature of parent/guardian\nDrug Testing Consent Letter & Malayan Insurance Form', '1191 Pablo Ocampo Sr. Extension, Brgy. Sta. Cruz, Makati City\nAdmissions Email: admissions@mapua.edu.ph\nDirect Line: +632.8891.0790\nTrunk Line: +632.8247.5000 local 71220\nWebsite: www.mapua.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48');
INSERT INTO `universities` (`id`, `name`, `type`, `location`, `description`, `campus_branches`, `tuition_fees`, `exam`, `requirements`, `enrollment_requirements`, `contact_links`, `created_at`, `updated_at`) VALUES
(67, 'San Carlos Seminary', 'Private', 'Makati', 'Founded in 1702, a private Catholic institution dedicated to training men to become priests. A formation house where seminarians live, pray, and study together focusing on human, spiritual, intellectual, and pastoral growth.', 'SCS San Carlos Pastoral Formation Complex\nSCS EDSA\nSCS Guadalupe Viejo', '₱30,000 – ₱50,000 per semester (includes board and lodging)\nMost seminarians are sponsored by home parish or Diocese. Full Grants-in-Aid available for those truly called but unable to afford fees.', 'Vocation Discernment Seminar required before exam. Entrance Exam held January to May covering English, Math, and basic IQ/Logic. Psychological Evaluation required to ensure emotional and mental readiness for seminary life.', 'Recommendation Letter from Parish Priest\nBaptismal & Confirmation Certificates (original copies)\nGrade 12 Report Card (SF9)\nParent\'s Canonical Marriage Contract', 'PSA Birth Certificate\nMedical Certificate (physically fit for rigorous schedule)\nSeminary Weekend Experience (SWD) – stay-in orientation before officially enrolling', 'San Carlos Pastoral Formation Complex, 912 EDSA, Guadalupe Viejo, Makati City\nLandline: (02) 8895-8855 / 8896-0583\nEmail: admissions@scs.edu.ph\nWebsite: www.scs.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(68, 'School of Fashion and the Arts', 'Private', 'Makati', 'A private specialized design school in Makati famous for Fashion Design and Interior Design programs. Treats design as both an art and a business. Has a partnership with IE University in Spain.', 'One and only campus at Rockwell Center, Makati City', 'Degree Programs: ~₱110,000 – ₱140,000 per semester\nAnnual total: ~₱220,000 – ₱280,000\nInstallment plans: 2-part, 4-part, and 12-part payment plans available via partner apps like Bukas', 'Design Test to evaluate creative problem-solving ability rather than traditional math/science exam. Exams held throughout the year. Major testing date for 2026 intake: April 18, 2026.', 'SoFA Application Account (created via website portal)\n2x2 ID Photos (white background)\nGrade 12 Report Card (Form 138)\nPSA Birth Certificate', 'Reservation Fee: ₱20,000 (secures slot, deducted from total tuition)\nSubmission of original SHS records\nGood Moral Certificate', '2nd Level, Proscenium Retail Row, Rockwell Center, Makati City\nTelephone: 02-8244-1073\nMobile: +63917 501 8136 / +63917 539 7574 / +63917 595 9428\nEmail: admissions@sofa.edu.ph / frontdesk@sofa.edu.ph\nWebsite: sofa.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(69, 'The One Nation Entrepreneur School', 'Private', 'Makati', 'A private entrepreneurship college famous for its mentorship-based approach. Students are treated like founders and innovators from day one, building actual businesses and creative projects.', 'One and only campus in the Makati Business District', '₱70,000 – ₱90,000 per semester\nAnnual total: ~₱140,000 – ₱180,000\nFull cash payment discounts available\nFounder Scholarships for exceptional business ideas or high SHS grades', 'Diagnostic Interview and Portfolio Review rather than a traditional math/science exam. Admissions are rolling (ongoing). For August 2026 intake, apply between February and June 2026.', 'Online Application Form (from official website or social media)\nPersonal Statement/Essay about business ideas or entrepreneurial goals\nGrade 11 & 12 Report Cards', 'Original Grade 12 Report Card (Form 138)\nOriginal PSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID Photos (white background)\nReservation Fee: ~₱5,000 – ₱10,000', '55 Paseo de Roxas, Urdaneta Village, Makati\nPhone: +63 282503610\nEmail: info@one.edu.ph\nRegistrar: registrar@laicollege.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(70, 'Pateros Technological College', 'LUC', 'Pateros', 'A local community college founded in 1993 focused on practical training in IT, Business, and Office Management. Provides strong education for students with limited budget.', 'One and only main campus', 'UniFAST Students: Free tuition for qualified local residents\nNon-UniFAST paying students: ₱150 – ₱300 per unit\nMiscellaneous Fees: ~₱2,000 – ₱4,000 per semester', 'Entrance Aptitude Exam testing basic Math, English, and Logic. Usually held April to July. Must visit campus to get Examination Permit first.', 'Form 138B (SHS Grade 12 card)\nForm 137\nPSA Birth Certificate (Photocopy)\nCertificate of Good Moral Character (Original)\nRecent 2x2 Picture (white background)\nLong folder with plastic jacket', 'Step 1: Submit requirements at Office of the College Registrar (documents in closed white long folder with plastic cover)\nStep 2: Assessment Office – applicable fees assessed\nStep 3: Cash Office – Payment of LMS (₱300), Tuition, Miscellaneous, and other fees\nStep 4: MIS Office – Obtain PTC institutional email and print School ID\nStep 5: CESJS Office – Submit Student Commitment Form\nVoter\'s ID/Certificate required for Pateros residents to get free tuition\nMedical Certificate may be required for AHRT students', 'College St., Sto. Rosario Kanluran, Pateros, Metro Manila\nPhone: (02) 640-5375 / 640-5389 / 642-8896\nEmail: ptc@paterostechnologicalcollege.edu.ph\nAdmissions: admissions@paterostechnologicalcollege.edu.ph\nWebsite: www.paterostechnologicalcollege.edu.ph', '2026-05-03 18:06:48', '2026-05-03 18:06:48'),
(72, 'Southeastern College', 'Private', 'Pasay', 'A private college in Pasay that offers business, education, computer, and hospitality-related programs. Known for affordable tuition and practical skills-based education.', 'Main campus in Pasay only', '₱20,000–₱40,000 per semester depending on the course', 'Entrance exam/interview depending on program.', 'Form 138 / Report Card\nPSA Birth Certificate\nGood Moral Certificate\n2x2 ID Pictures\nEntrance exam/interview (depends on program)', NULL, 'Address: Pasay City, Metro Manila\nTelephone: (02) 8831-8089', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(73, 'San Juan de Dios Educational Foundation, Inc.', 'Private', 'Pasay', 'A Catholic institution focused mainly on healthcare and allied medical programs such as Nursing, Medical Technology, and Physical Therapy.', 'Main campus only', '₱35,000–₱80,000+ per semester depending on medical/allied health programs', 'Entrance exam and interview required.', 'Grade 12 report card/Form 138\nPSA Birth Certificate\nGood Moral Certificate\n2x2 ID pictures\nEntrance exam & interview', NULL, 'Address: 2772 Roxas Blvd., Pasay City\nTelephone: +63 2 8551-2763\nEmail: admission_office@sjdefi.edu.ph', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(74, 'STI College Pasay-EDSA', 'Private', 'Pasay', 'Began as a computer training center in 1983 and has since grown into a massive network of academic centers. Famous for its Industry-Driven Curriculum, partnering with big companies like Microsoft and Huawei to ensure classroom learning matches real-world work.', 'STI College Caloocan\nSTI College Cubao\nSTI College Fairview\nSTI College Muñoz-EDSA\nSTI College Novaliches\nSTI College Sta. Mesa\nSTI College Alabang\nSTI College Las Piñas\nSTI College Makati\nSTI College Marikina\nSTI College Ortigas-Cainta', 'Estimated Total per Semester: ₱30,000 – ₱45,000 depending on the course and campus location. STI Open Scholarship (SOS): Partial to full tuition grants. GSIS/Pag-IBIG Benefit: 10%–20% tuition subsidies. Honor Student Discount available.', 'STI Student Career Optimization Test (SCOT). Fee: Usually Free or included in the application fee (around ₱250 – ₱500). Exams are ongoing year-round.', 'Original Form 138 / SF9-SHS (Learner\'s Progress Report Card)\nOriginal Form 137 / SF10-SHS (Learner\'s Permanent Academic Record)\nPSA-issued Birth Certificate\nOriginal Copy of Certificate of Good Moral Character\nMedical Certificate of Chest X-ray results', NULL, 'Address: STI Academic Center, #2818 EDSA Extension corner P. Celle Street, Barangay 75, San Rafael, Pasay City, 1302 Metro Manila\nTelephone: 8722-5698\nWebsite: https://www.sti.edu/campuses-details.asp?campus_id=VEFG', '2026-05-09 15:48:43', '2026-05-09 16:40:23'),
(75, 'National University MOA', 'Private', 'Pasay', 'A modern NU campus near Mall of Asia offering strong programs in engineering, technology, business, health sciences, and multimedia arts.', 'NU Manila\nNU Fairview\nNU Dasmariñas\nNU Baliwag\nNU Laguna\nNU Clark\nand more nationwide', '₱20,000–₱50,000+ per term depending on course/program', 'Online registration through NU admissions portal.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nCertificate of Graduation\nOnline registration through NU admissions portal', NULL, 'Address: Coral Way St., Mall of Asia Complex, Pasay City\nContact: (02) 8355-1206 loc. 3200', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(76, 'Manila Tytana Colleges', 'Private', 'Pasay', 'A healthcare-centered college in Pasay recognized for Nursing and Medical Technology, with additional business and hospitality programs.', 'Main campus only', '₱50,000–₱120,000+ per semester depending on healthcare programs', 'Entrance exam and interview required.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nEntrance exam/interview', NULL, 'Address: Diosdado Macapagal Blvd., Pasay City\nTelephone: (02) 8859-0888', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(77, 'Arellano University – Jose Abad Santos Campus', 'Private', 'Pasay', 'An Arellano branch in Pasay offering health sciences, criminology, IT, education, and business-related courses at relatively affordable tuition.', 'Legarda Campus\nAndres Bonifacio Campus\nJuan Sumulong Campus\nPlaridel Campus\nElisa Esguerra Campus', '₱30,000–₱70,000 per semester depending on course', 'Entrance exam required.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nEntrance exam', NULL, 'Address: Pasay City, Metro Manila\nTelephone: (02) 8404-3089', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(78, 'Asian Institute of Maritime Studies', 'Private', 'Pasay', 'A maritime-focused school specializing in Marine Transportation and Marine Engineering for students pursuing careers at sea.', 'Main campus only', '₱40,000–₱100,000+ depending on maritime course', 'Entrance exam and interview required.', 'Form 138\nPSA Birth Certificate\nMedical exam\nEntrance exam/interview', NULL, 'Address: Roxas Blvd., Pasay City\nTelephone: (02) 8521-0670', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(79, 'Air Link International Aviation College', 'Private', 'Pasay', 'An aviation-oriented school in Pasay offering aircraft maintenance, aviation electronics, tourism, and airline-related training programs.', 'Main campus only', '₱40,000–₱120,000+ depending on aviation program', 'Interview and medical exam required.', 'Form 138\nPSA Birth Certificate\nMedical exam\nInterview', NULL, 'Address: Pasay City, Metro Manila\nTelephone: (02) 8853-9634', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(80, 'Philippine State College of Aeronautics', 'SUC', 'Pasay', 'A state college specializing in aviation and aerospace education, PhilSCA is one of the top aviation schools in the Philippines known for producing graduates in Aeronautical Engineering, Aircraft Maintenance, and Air Transportation. Ideal for students pursuing careers as pilots, aircraft engineers, technicians, and aviation managers.', 'Villamor Campus (Pasay) – Main', 'Free tuition (State College / covered under Universal Access to Quality Tertiary Education for qualified students). Minimal miscellaneous fees may apply.', 'Applicants must pass the PhilSCA Admission Test and screening/interview depending on program.', 'Online application form\nForm 138 / Grade 12 report card\nPSA Birth Certificate\nGood Moral Certificate\nPass PhilSCA Admission Test and screening/interview (depending on program)', NULL, 'Address: Piccio Garden, Villamor, Pasay City\nWebsite: NAAP Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(82, 'AMA Computer College – Parañaque', 'Private', 'Parañaque', 'A technology-focused college known for IT, Computer Science, multimedia, and business programs with computer-based learning.', 'Caloocan\nFairview\nQuezon City\nMakati\nPasay\nLas Piñas', '₱25,000–₱60,000 per semester depending on program', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID Pictures', NULL, 'Address: Parañaque City\nOfficial Website: AMA Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(83, 'Datamex College of Saint Adeline – Parañaque', 'Private', 'Parañaque', 'A private institution offering IT, business, education, hospitality, and criminology programs with affordable tuition options.', 'Caloocan\nValenzuela\nLas Piñas\nTaguig', '₱20,000–₱45,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID Pictures', NULL, 'Address: Parañaque City\nOfficial Website: Datamex Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(84, 'Immaculate Heart of Mary College – Parañaque', 'Private', 'Parañaque', 'A Catholic-based private school offering education, business, IT, psychology, and hospitality-related programs.', 'Main campus only', '₱20,000–₱50,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID Pictures', NULL, 'Address: Parañaque City\nOfficial Website: IHMC Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(85, 'Universal Colleges of Parañaque', 'Private', 'Parañaque', 'A private college known for Nursing, Pharmacy, Criminology, IT, education, and hospitality programs.', 'Main campus only', '₱25,000–₱60,000 per semester', 'No entrance exam required. Submit admission requirements to enroll.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID Pictures', NULL, 'Address: Parañaque City\nOfficial Website: Universal Colleges of Parañaque Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(86, 'PATTS College of Aeronautics', 'Private', 'Parañaque', 'One of the well-known aviation schools in the Philippines specializing in Aeronautical Engineering, Aircraft Maintenance, Air Transportation, and aviation technology programs.', 'Main campus only (Parañaque)', '₱50,000–₱150,000+ per semester depending on aviation program and laboratory/training fees', 'Entrance exam, medical exam, and interview required.', 'Form 138\nPSA Birth Certificate\nGood Moral Certificate\nMedical exam\nInterview\nEntrance exam', NULL, 'Address: Lombos Ave., Parañaque City\nOfficial Website: PATTS College of Aeronautics Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(87, 'City of Malabon University', 'LUC', 'Malabon', 'A public local university funded by the Malabon local government that provides free or low-cost quality education primarily for Malabon residents, offering programs in education, business, criminology, IT, social sciences, and graduate studies.', 'Main campus only (Longos, Malabon)', 'Free tuition for qualified residents under local/state subsidy.', 'Applicants must take and pass the CMUCAT (City of Malabon University College Admission Test).', 'Accomplished application form\nPSA Birth Certificate\nGrade 11 Report Card (Form 138/SF9)\nGrade 12 Report Card (if available)\nFor transferees: Transcript of Records\nTake/pass CMUCAT (City of Malabon University College Admission Test)', NULL, 'Address: Pampano cor. Maya-Maya Sts., Longos, Malabon City\nEmail: cmuofficial@cityofmalabonuniversity.edu.ph / ro@cityofmalabonuniversity.edu.ph\nWebsite: City of Malabon University Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(88, 'Arellano University – Malabon Campus', 'Private', 'Malabon', 'A private university known for its strong health-related programs such as Nursing, Pharmacy, and Medical Technology, while also offering programs in business, education, hospitality, and criminology. Part of the larger Arellano University system with multiple campuses in Metro Manila.', 'Juan Sumulong (Legarda, Manila)\nAndres Bonifacio (Pasig)\nJose Rizal (Pasay)\nPlaridel (Mandaluyong)', '₱30,000–₱60,000 per semester (depends on course)', 'Entrance exam/interview if required.', 'Form 138 / Report Card\nGood Moral Certificate\nPSA Birth Certificate\n2x2 ID pictures\nEntrance exam/interview (if required)', NULL, 'Address: Gov. Pascual Ave., Malabon City\nWebsite: Arellano University', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(89, 'De La Salle Araneta University', 'Private', 'Malabon', 'A private Lasallian university in Malabon recognized for its specialization in Veterinary Medicine and Agriculture, making it unique among universities in Metro Manila. Also offers business, education, psychology, and technology-related programs.', 'San Jose del Monte, Bulacan extension campus', '₱45,000–₱90,000+ per semester depending on program', 'Application form and document submission required. Entrance exam/interview may apply depending on program.', 'Application form\nForm 138 / TOR\nPSA Birth Certificate\nGood Moral Certificate\n2x2 ID photos', NULL, 'Address: 302 Victoneta Ave., Potrero, Malabon City\nTel: (+632) 8330-9128\nEmail: info@dlsau.edu.ph\nWebsite: DLSAU Official Website', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(90, 'College of Saint Amatiel', 'Private', 'Malabon', 'A private college in Malabon focused on providing affordable and accessible education, offering programs mainly in information technology, business, education, and hospitality, along with technical-vocational courses.', 'Main campus only (Malabon)', '₱20,000–₱40,000 per semester (varies by course)', 'No highly competitive entrance exam. Submit admission requirements to enroll.', 'Form 138 / Transcript\nGood Moral Certificate\nPSA Birth Certificate\nID pictures', NULL, 'Location: Malabon City\nFacebook / direct inquiry recommended (official website limited)', '2026-05-09 15:48:43', '2026-05-09 15:48:43'),
(91, 'Pamantasan ng Lungsod ng Marikina (PLMar)', 'LUC', 'Marikina', 'Pamantasan ng Lungsod ng Marikina (PLMar) is the first city-funded university in Marikina City, established in 2003 to provide affordable and quality education for Marikina residents. The university offers undergraduate, graduate, and Senior High School programs while developing competent and community-oriented graduates.', 'Main campus only (SSS Village, Concepcion Dos, Marikina City)', 'Free / fully subsidized under RA 10931', 'PLMar College Admission Test (PCAT). Application period January 30 – February 20, 2026. Admission based on GWA, PCAT result, and interview. Online application through PLMar Admission Portal required.', 'Scanned copy of Grade 12 Report Card (Form 138)\nPSA Birth Certificate (photocopy)\nProof of Residency (valid government ID of student/parent or proof of billing)\n2 pcs. recent 2x2 ID picture (white background)\nCertificate of Non-Issuance of Numerical Grades (if applicable)', 'Submit original documents at PLMar Admission Office (SSS Campus) on assigned appointment schedule:\nPSA Birth Certificate\nGood Moral Certificate\nTransfer Credentials (for transferees)\nTransferees: TOR or Certified True Copy of Grades, Honorable Dismissal, Form 138\nNote: Only 2nd or 3rd year transferees are accepted.', 'Rainbow St. cor. Russet St., SSS Village, Concepcion Dos, Marikina City, Metro Manila, Philippines 1800\nTel: 369-7277 / 586-3586 / (02) 7577-0597\nContact No.: (+639)17 638 2689\nEmail: plmaradmission@gmail.com / plmarikina2003@yahoo.com.ph\nFacebook: @PLMAR2003ADMISSION', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(92, 'Marikina Polytechnic College (MPC)', 'SUC', 'Marikina', 'Marikina Polytechnic College (MPC) is a state-funded higher education institution in Marikina City specializing in technical-vocational teacher education, engineering, and industrial technology. Founded in 1947, it serves as a premier center for developing highly skilled technicians and educators, ensuring students are equipped for both local and global industries.', 'Main campus only (Sta. Elena, Marikina City)', 'Free / fully subsidized under RA 10931 (Universal Access to Quality Tertiary Education Act)', 'Marikina Polytechnic College Admission Test (MPCAT). Online application: February 24 – March 14, 2026. Hardcopy submission: March 17 – April 11, 2026. MPCAT date selected after document verification. Applicants must print and bring their Test Permit on exam day.', 'Online Registration via MPC Admission College Information System\nScanned copy of Latest Report Card\nScanned copy of Certificate of Good Moral Character\nALS/PEPT Passers: Scanned copy of Certificate of Rating\n3 pieces of 2x2 ID picture (white background with name tag) for hardcopy submission', 'Visit campus March 17 – April 11 for hardcopy verification:\nPhotocopies of uploaded documents\n3 pcs. 2x2 ID picture (white background with name tag)\nTransferees: TOR or COG, Good Moral Certificate, Honorable Dismissal, 3 pcs. 2x2 ID picture', '#2 Mayor Chanyungco St., Sta. Elena, Marikina City, Philippines 1800\nTel: (02) 8681-9293\nWebsite: mpc.edu.ph\nFacebook: @MPCOfficialAdmissionAndScholarship', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(93, 'Datamex College of Saint Adeline – Marikina', 'Private', 'Marikina', 'Datamex College of Saint Adeline – Marikina is a private educational institution and a member of the Datamex Computer Education System. It is recognized for providing accessible and industry-oriented education in the fields of information technology, business, and hospitality management. The Marikina campus focuses on equipping students with practical skills through a combination of theoretical learning and hands-on laboratory experience.', 'Datamex Parañaque (Sucat)\nDatamex Fairview (Quezon City)\nDatamex Novaliches (Quezon City)\nDatamex Pasay\nDatamex Manila (Legarda)', '₱15,000–₱25,000 per semester. Known for \"Zero Tuition\" programs for SHS graduates (terms and conditions apply).', 'No competitive entrance exam. Rolling admission typically April to August for 1st Semester. Visit campus or message official Facebook page to apply.', 'Grade 12 Report Card (Form 138 - Original and Photocopy)\nPSA Birth Certificate (Photocopy)\nCertificate of Good Moral Character (Original)\n4 pieces of 2x2 ID picture (White background)\n2 pieces of 1x1 ID picture (For student ID)\nTransferees: TOR or Honorable Dismissal, subject description from previous school', 'Step 1: Inquiry and Application – Visit campus or Facebook page, accomplish Enrollment/Application Form from Registrar\nStep 2: Submission of academic documents\nStep 3: Proceed to Accounting Office for fee assessment\nStep 4: Pay required downpayment or full tuition at cashier, secure Official Receipt\nStep 5: Present OR to Registrar for validation, proceed to ID section for photo capture', '350 J.P. Rizal St., Brgy. Sto. Niño, Marikina City, Metro Manila, Philippines\nTel: (02) 8948-2615 / (02) 7089-7516\nEmail: datamexmarikina@gmail.com\nFacebook: @DatamexMarikinaOfficial', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(94, 'La Consolacion College – Marikina', 'Private', 'Marikina', 'La Consolacion College Marikina is a private Catholic educational institution managed by the Augustinian Sisters of Our Lady of Consolation. It focuses on a faith-based curriculum that integrates academic excellence with spiritual and moral formation, serving as a dedicated hub for students in the eastern part of Metro Manila and producing socially responsible and professionally competent graduates.', 'La Consolacion College Manila (Mendiola)\nLa Consolacion College Novaliches (Caloocan)\nLa Consolacion College Caloocan\nLa Consolacion College Pasig', '₱35,000–₱50,000 per semester (varies significantly by program and year level)', 'Institutional entrance exam required. Testing fee must be paid to secure a schedule. Interview with Department Dean or Program Head after the exam.', 'Form 138 (Senior High School Report Card)\nPSA Birth Certificate (Photocopy)\nCertificate of Good Moral Character\n2 pieces of 2x2 ID picture (White background)', 'Pay testing fee and secure entrance exam schedule\nTake institutional entrance exam\nUndergo interview with Department Dean or Program Head\nFill out official Enrollment Form\nPay required downpayment at the cashier', '46 Guerilla St., Sto. Niño, Marikina City, Metro Manila, Philippines\nTel: (02) 8941-2605 / 8941-6571\nWebsite: https://www.lccm.edu.ph\nFacebook: @LCCMarikinaOfficial', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(95, 'FEU Roosevelt – Marikina', 'Private', 'Marikina', 'Far Eastern University Roosevelt Marikina is a private university campus of the FEU system known for quality education, modern facilities, and strong academic programs. Established in 1928, FEU offers undergraduate and graduate courses and is recognized for producing competent, innovative, and globally competitive graduates.', 'FEU Roosevelt Cainta\nFEU Roosevelt Rodriguez', '₱60,000–₱90,000+ per semester depending on the program', 'FEU College Admissions Test (FEUCAT) required. Pay ₱500 FEUCAT fee and book exam schedule online. Only qualified FEUCAT passers can proceed to enrollment.', 'Apply online through FEU Roosevelt admission portal\n2x2 ID picture (white background)\nFEUCAT application fee payment (₱500)\nForm 138 (Report Card)\nPSA/NSO Birth Certificate (photocopy)\nCertificate of Good Moral Character', 'After FEUCAT results:\nComplete Enrollment Information form\nUpload Form 138, Form 137, PSA Birth Certificate, Good Moral Certificate, 2x2 ID pictures\nSelect program and class schedule\nEnroll in subjects via Manage Enrollment portal\nPay tuition through FEU Roosevelt payment channels', 'J.P. Rizal St., Lamuan, Marikina City\nTel: +632 8941-4093\nMobile: +63960-558-1889\nFacebook: https://www.facebook.com/FEURooseveltMar', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(96, 'National Christian Life College', 'Private', 'Marikina', 'National Christian Life College is a private educational institution in Marikina City that provides college education along with basic education, focusing on Christian values and academic development.', 'Main campus only (Marikina City)', '₱25,000–₱50,000+ per year', 'Entrance examination may be required depending on program. Interview and assessment conducted.', 'Application Form from school\n2x2 ID pictures (white background)\nForm 138 (Senior High School Report Card)\nCertificate of Good Moral Character\nPSA/NSO Birth Certificate (photocopy)\nEntrance examination (if required depending on program)', 'Submit complete requirements at admissions/registrar office\nUndergo interview and assessment if required\nFinal approval from registrar/admissions office\nPayment for enrollment confirmation', 'Marikina City, Metro Manila, Philippines\nLandline: (02) 941-7401\nMobile: 0910-626-1447\nEmail: nationalchristianlifecollege@yahoo.com', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(97, 'STI College Marikina', 'Private', 'Marikina', 'STI College Marikina is part of the STI network of schools in the Philippines offering college programs focused on IT, business, hospitality, and tourism education. It follows a standardized STI curriculum designed to prepare students for employment and industry-based careers.', 'STI College Makati\nSTI College Quezon Avenue\nSTI College Ortigas-Cainta\nSTI College Global City', '₱45,000–₱60,000 per semester depending on program and year level', 'No competitive entrance exam for most programs. Admission is based on evaluation of submitted academic records. Possible interview depending on program.', 'Form 138 (Senior High School Report Card)\nForm 137 (Permanent Academic Record)\nPSA Birth Certificate (photocopy)\nCertificate of Good Moral Character\nMedical requirements may be requested depending on program\nTransferees: TOR or Certified True Copy of Grades, Certificate of Honorable Dismissal, PSA Birth Certificate, Good Moral Certificate', 'Fill out STI application form (online or onsite)\nSubmit admission requirements\nReview of submitted academic records and possible interview\nPay required enrollment fees\nReceive official confirmation of enrollment', '289 L. de Guzman Street, Concepcion I, Marikina City, 1807 Metro Manila, Philippines\nLandline: (02) 8942-3307\nEmail: inquiry@marikina.sti.edu', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(98, 'Our Lady of Perpetual Succor College (OLOPSC)', 'Private', 'Marikina', 'Our Lady of Perpetual Succor College (OLOPSC) is a private, non-sectarian educational institution in Marikina City offering basic education and higher education programs. Its college department provides programs in education, business, tourism, hospitality, and computing studies, focusing on academic development and professional readiness.', 'Main campus only (Concepcion Uno, Marikina City)', '₱25,000–₱45,000 per semester depending on program and year level', 'Entrance exam required. Application fee of ₱300. Interview conducted by the school after exam. Evaluation by Guidance Department based on submitted documents and interview performance.', 'Duly accomplished Personal Data Sheet (PDS)\nPSA/NSO Birth Certificate (photocopy)\nLatest Report Card or Certification of Grades / Transfer Credentials\nCertificate of Good Moral Character\nTwo (2) pieces 2x2 ID photo (white background)\nCertificate of NSTP completion with serial number (for NSTP graduates only)\nApplication fee: ₱300', 'Step 1: Submit requirements at OLOPSC Main Registrar\'s Office\nStep 2: Pay ₱300 application fee at cashier\nStep 3: Attend scheduled interview\nStep 4: Wait for evaluation result from Guidance Department\nStep 5: Submit remaining requirements; submit original Final Report Card or Transfer Credentials; proceed to official enrollment once cleared', 'Gen. Ordoñez St., Concepcion Uno, Marikina City, 1807 Philippines\nTelephone/Mobile: +63 960 563 0970\nEmail: admissions@olopsc.edu.ph\nFacebook: OLOPSC Official Page', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(99, 'Pamantasan ng Lungsod ng Valenzuela (PLV)', 'LUC', 'Valenzuela', 'Pamantasan ng Lungsod ng Valenzuela (PLV) is a local government-funded public university established in 2002. It is dedicated to providing high-quality, subsidized tertiary education to the residents of Valenzuela. With its state-of-the-art Maysan campus and specialized annexes, PLV has become a center for academic excellence in engineering, business, and social sciences.', 'Main campus (Tongco St., Brgy. Maysan, Valenzuela City)', 'Free / fully subsidized under RA 10931 for qualified Valenzuelano residents', 'PLV College Admission Test (PLV-CAT). Application starts January 2026. Examination period March–April 2026. Applicants must have a GWA of at least 80%. Priority given to bona fide Valenzuela City residents. Qualified exam passers undergo interview with respective College Deans.', 'Photocopy of Grade 12 Report Card (Form 138)\nTwo (2) pieces of 1x1 ID picture\nEntrance Exam Fee (if applicable)\nProof of Residency: Voter\'s ID of Parent/Applicant or COMELEC Certification', 'Submit original documents after passing PLV-CAT and interview:\nPSA Birth Certificate (original)\nGood Moral Certificate (original)\nTransfer Credentials (for transferees)', 'Tongco St., Brgy. Maysan, Valenzuela City, Metro Manila\nTel: (02) 8352-1000\nEmail: plv_admissions@valenzuela.gov.ph\nWebsite: valenzuela.plv.edu.ph\nFacebook: @PamantasanNgLungsodNgValenzuela', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(100, 'Our Lady of Fatima University – Valenzuela', 'Private', 'Valenzuela', 'Our Lady of Fatima University (OLFU) is a premier private university in the Philippines, widely recognized for its excellence in paramedical and healthcare education. Founded in 1967 as a nursing school, it has since achieved Autonomous Status from CHED. The Valenzuela campus serves as the university\'s main hub, housing the College of Medicine and state-of-the-art simulation laboratories.', 'OLFU Quezon City (Lagro and Regalado)', 'Undergraduate programs: ₱30,000–₱45,000 per semester. Medicine/Dentistry: Higher rates apply due to specialized equipment and clinical rotations. Minimum Downpayment: ₱1,500 (plus ₱500 application fee).', 'Fatima University Admission Test (FUAT) required. Application starts as early as November for the following academic year. Scholarship Exam usually scheduled in February and March. Register via OLFU Student Admission portal and select Valenzuela Campus.', 'Register via OLFU Student Admission portal\nSelect \"Valenzuela Campus\" and upload 2x2 ID picture (white background)\nPay ₱500 non-refundable application fee\nGrade 12 Report Card (Form 138)\nPSA Birth Certificate (Photocopy)\nCertificate of Good Moral Character\n2x2 ID Pictures (4 pieces)', 'Take FUAT (Fatima University Admission Test)\nSome health programs may require additional interview or higher score for qualification\nPay minimum downpayment (₱1,500) to officially secure slot and generate Certificate of Matriculation (COM)', 'RISE Tower, Fatima Avenue corner MacArthur Highway, Brgy. Marulas, Valenzuela City\nTel: (02) 8291-6538 / 8291-6644\nEmail: admissions-val@fatima.edu.ph\nWebsite: https://fatima.edu.ph\nFacebook: @OLFUValenzuelaAdmissions', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(101, 'St. Louis College – Valenzuela (SLCV)', 'Private', 'Valenzuela', 'St. Louis College-Valenzuela is a private, Christian higher education institution founded in 1976. It is dedicated to providing quality education imbued with Christian values, guided by its motto \"Wisdom, Charity, Truth.\" The college is known for its strong focus on practical, industry-aligned programs in business, technology, and hospitality.', 'Main campus only (Valenzuela City)', '₱25,000–₱40,000 per semester depending on program and year level. 15–20% discount on tuition for the 3rd, 4th, or 5th child in a family enrolled in the institution.', 'Institutional assessment/entrance exam required. Pay testing fee and undergo exam. Personality test and interview with Department Head or Guidance Counselor conducted after exam.', 'Grade 12 Report Card (Form 138 - Original)\nPSA Birth Certificate (Photocopy)\nCertificate of Good Moral Character (Original)\n2 pieces of 2x2 ID picture (White background)\n1 piece of 1x1 ID picture\nTransferees: TOR or Informative Copy of Grades, Honorable Dismissal or Transfer Credentials, Subject descriptions (if requesting credit of previous subjects)', 'Step 1: Secure application form, pay testing fee, and take institutional assessment exam\nStep 2: Submit basic documents at Registrar\'s Office\nStep 3: Undergo personality test and interview with Department Head or Guidance Counselor\nStep 4: Complete enrollment form, proceed to Accounting Office for fee assessment, pay downpayment or full tuition at cashier to receive Registration Form', '#005 Maysan Road, Valenzuela City, 1440 Metro Manila, Philippines\nTel: (02) 292-0481 / 292-3121 / 292-3170\nEmail: slcv@vasia.com\nWebsite: https://www.slcv.edu.ph\nFacebook: @SLCV.Official', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(102, 'Our Lady of Lourdes College (OLLC)', 'Private', 'Valenzuela', 'Our Lady of Lourdes College is a private educational institution offering CHED-recognized college programs across health sciences, business, education, IT, arts, and social sciences. It focuses on professional training and academic development for licensure and industry readiness.', 'Main campus only (Gen. T. de Leon, Valenzuela City)', '₱20,000–₱40,000 per semester (varies per program and year level)', 'OLLC entrance exam required. Schedule provided by admissions office. Possible interview depending on program. Evaluation of academic records and exam result conducted.', 'Accomplished application form from OLLC\n2x2 ID picture (white background)\nForm 138 (Senior High School Report Card)\nCertificate of Good Moral Character\nPSA Birth Certificate (photocopy)\nEntrance examination (schedule provided by admissions office)', 'Submit complete requirements\nTake OLLC entrance exam\nWait for evaluation result from admissions\nPay enrollment fees\nReceive official enrollment confirmation', 'Gen. T. de Leon, Valenzuela City, Metro Manila, Philippines\nLandline: (02) 8922-0077\nEmail: info@ollc.edu.ph\nWebsite: https://www.ollc.edu.ph', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(103, 'Saint Catherine College – Valenzuela', 'Private', 'Valenzuela', 'Saint Catherine College of Valenzuela is a private educational institution in Valenzuela City offering basic education, TESDA technical programs, and selected college programs. It focuses on skills-based education, teacher training, business, IT, and allied programs.', 'Main campus only (Mapulang Lupa, Valenzuela City)', '₱20,000–₱40,000 per semester (varies per program and year level)', 'Entrance exam may be required depending on program. Admission interview and evaluation of academic records conducted by admissions office.', 'Accomplished application form\n2x2 ID picture (white background)\nForm 138 (Senior High School Report Card)\nCertificate of Good Moral Character\nPSA Birth Certificate (photocopy)\nTransfer Credentials (for transferees)\nEntrance exam (if required depending on program)', 'Submit application form and requirements at Admissions/Registrar Office\nUndergo admission interview and evaluation\nSubmit complete requirements\nPay application/enrollment fees\nFinal enrollment confirmation from registrar', 'P-5 130 Cunanan Compound / Sto. Rosario, Mapulang Lupa, Valenzuela City, Philippines\nTelephone: (02) 3443-1860 / (02) 7118-0611\nEmail: stcatharineschool@yahoo.com\nWebsite: https://stcatharineschool.com', '2026-05-09 16:03:54', '2026-05-09 16:03:54'),
(104, 'University of the Philippines - Diliman (UP Diliman)', 'SUC', 'Quezon City', 'The flagship campus of the UP System located in Quezon City. Widely regarded as one of the top universities in the Philippines, known for excellence in academics, research, and public service. UP Diliman offers a wide range of undergraduate and graduate programs across various disciplines.', 'UP Los Baños (Laguna)\nUP Manila (health sciences)\nUP Visayas\nUP Baguio\nUP Mindanao\nUP Cebu\nUP Open University (distance learning)', 'UP follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Some fees may still apply (miscellaneous, lab, etc.).', 'Take the UP College Admission Test (UPCAT), administered once a year (usually August). Scores are combined with high school grades to determine qualification. Must be graduating from Senior High School (Grade 12) or already a graduate. Must have complete grades from Grades 8–11. Must not have taken any college subjects yet. Must not have previously taken the UPCAT or applied to UP.', 'Form 1 – Personal Data Sheet (online submission)\nForm 2B – High School Record (submitted by school)\nValid email address\nOfficial copies may be required for final verification\nAfter passing UPCAT:\nOfficial High School Transcript (original copy)\nPSA Birth Certificate (original + photocopy)\nMedical Certificate (UP Health Service/accredited clinic)\nStudent Directory / personal data forms\nPassport-size photos', 'Notice of Admission (NOA)\nOriginal Form 138 / Report Card (with eligibility for college)\nCertificate of Graduation (if not yet included in Form 138)\nUP Student Directory / Registration Forms\nMedical Clearance (from UP Diliman Health Service)\n2x2 or passport-size ID photos\nValid ID (for verification)\nNote: Some colleges may require placement exams or interviews. Enrollment is done through UP\'s online system (CRS – Computerized Registration System).', 'Address: Kalaw St. corner Quirino Ave., UP Diliman, Quezon City\nPhone: +63 2 8981-8500\nEmail: upcollegeapplications.oadms@up.edu.ph\nWebsite: https://upcat.up.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(105, 'Polytechnic University of the Philippines - Quezon City (PUP QC)', 'SUC', 'Quezon City', 'Known for providing affordable and quality education, especially in business, technology, and public service programs. PUP QC focuses on producing practical, skilled, and industry-ready graduates.', 'PUP Sta. Mesa (Main Campus)\nPUP Taguig\nPUP San Juan\nPUP Parañaque\nPUP Bataan\nPUP Bulacan\nPUP Cavite\nPUP Laguna\nPUP Batangas\nPUP Quezon Province\nPUP Maragondon', 'PUP follows the Free Tuition Law (RA 10931) → most students pay ₱0 tuition. Minimal fees may still apply (miscellaneous, ID, etc.). Very affordable compared to private universities.', 'Take the PUP College Entrance Test (PUPCET), conducted once a year (usually early months of the year). Results determine qualification together with available slots. Must be a Grade 12 graduating student or SHS graduate. Must have completed Senior High School (K-12). Must not have taken college units.', 'Accomplished Application Form (iApply)\nGrade 11 Report Card (or latest grades)\nRecent ID picture\nValid email address\nAdditional documents may be required for verification\nAfter passing PUPCET:\nOriginal Grade 12 Report Card (Form 138)\nPSA Birth Certificate (original + photocopy)\nCertificate of Good Moral Character\nMedical Certificate\nPassport-size photos', 'Notice of Admission / Qualified Slip\nOriginal Form 138 (Report Card)\nCertificate of Graduation\nGood Moral Certificate\nMedical Clearance\nID photos (2x2 or passport-size)\nValid ID (for verification)\nNote: Admission depends on slot availability per course. Some programs may have interviews or screening. Enrollment follows a scheduled process by batch.', 'Address: Don Fabian St., Commonwealth, Quezon City\nPhone: (02) 8932-7427\nEmail: pupqc@pup.edu.ph\nWebsite: https://www.pup.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(106, 'Quezon City University (QCU)', 'LUC', 'Quezon City', 'A local government-funded university in Quezon City that provides free and quality education to residents. QCU focuses on technology, education, and business programs, aiming to produce competent, community-oriented, and industry-ready graduates.', 'QCU San Bartolome (Main Campus)\nQCU Batasan Campus\nQCU San Francisco Campus', 'QCU follows the Free Tuition Law (RA 10931) → most students pay ₱0 tuition. Primarily for Quezon City residents. Minimal fees may apply (ID, miscellaneous, etc.).', 'Take the QCU Admission Test (QCUAT), usually conducted once a year. Admission depends on exam results and available slots. Must be a Grade 12 graduating student or SHS graduate. Preferably a Quezon City resident. Must meet grade requirements set by QCU. Must not have taken college units yet.', 'Accomplished Application Form\nGrade 12 Report Card / Latest Grades\nRecent ID photo\nValid email address\nAfter passing:\nOriginal Grade 12 Report Card (Form 138)\nPSA Birth Certificate (original + photocopy)\nCertificate of Good Moral Character\nMedical Certificate\nPassport-size photos', 'Notice of Admission\nOriginal Form 138 (Report Card)\nCertificate of Graduation\nGood Moral Certificate\nMedical Clearance\nID photos (2x2 or passport-size)\nValid ID (for verification)\nNote: Priority is given to Quezon City residents. Some programs may have screening or interviews. Enrollment follows a scheduled batch system.', 'Address: San Bartolome, Novaliches, Quezon City\nPhone: (02) 8286-7837\nEmail: info@qcu.edu.ph\nWebsite: https://qcu.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(107, 'National Defense College of the Philippines (NDCP)', 'OGS', 'Quezon City', 'A premier government institution in the Philippines that provides advanced education in national security and public administration. NDCP focuses on developing leaders in the military, government, and private sector who are capable of handling national defense, security, and strategic policy-making.', 'NDCP has only one main campus (no branches)', 'Tuition varies depending on the program. Many students are sponsored by government agencies or are military/public officials. Some programs may be subsidized or funded.', 'No standard entrance exam like UPCAT/PUPCET. Admission is based on qualifications, work experience, and endorsements. Must be a college graduate. Preferably a government official, military officer, or professional with leadership experience.', 'Accomplished Application Form\nCollege Transcript of Records\nDiploma (Bachelor\'s Degree)\nResume / Curriculum Vitae\nRecommendation or endorsement letters\nRecent ID photos\nAfter acceptance:\nMedical clearance\nSecurity clearance (for some applicants)\nOfficial documents for enrollment processing', 'Notice of Admission\nOriginal academic documents\nMedical clearance\nID photos\nOther institutional forms\nNote: Programs are graduate-level only (no undergraduate courses). Students are often professionals, officers, or leaders. Focus is on policy-making, leadership, and national security.', 'Address: Camp General Emilio Aguinaldo, Quezon City\nPhone: (02) 8911-6001\nEmail: ndcp@ndcp.edu.ph\nWebsite: https://ndcp.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(108, 'Philippine Public Safety College (PPSC)', 'OGS', 'Quezon City', 'A government institution responsible for the education, training, and human resource development of public safety personnel in the Philippines. PPSC focuses on producing competent leaders in law enforcement, fire protection, jail management, and public safety administration.', 'National Police College (NPC)\nNational Fire Training Institute (NFTI)\nNational Jail Management and Penology Training Institute (NJMPTI)\nPublic Safety Basic Recruit Course units nationwide', 'Training programs are usually government-funded and sponsored by agencies (PNP, BFP, BJMP). Some courses may have minimal administrative fees.', 'No standard college entrance exam. Admission depends on agency endorsement (PNP, BFP, BJMP), qualifications, and rank (for officers). Must be a police officer, fire officer, jail officer, or government personnel in public safety. Must meet rank/training requirements and be physically and mentally fit.', 'Accomplished Application Form\nEndorsement from agency\nService record\nEducational background documents\nMedical clearance\nRecent ID photos\nAfter acceptance:\nSecurity clearance\nOfficial designation/order from agency\nAdditional training documents', 'Admission order / training order\nValid ID and service ID\nMedical and physical fitness clearance\nRequired uniforms and materials', 'Address: EDSA corner NIA Northside Road, Quezon City\nPhone: (02) 8725-0517\nEmail: info@ppsc.gov.ph\nWebsite: https://ppsc.gov.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(109, 'ABE International College of Business and Accountancy - Cubao', 'Private', 'Quezon City', 'A private educational institution in the Philippines that focuses on business, accountancy, hospitality, and technology programs. ABE aims to develop globally competitive, industry-ready graduates through practical training and international standards in education.', 'ABE Caloocan\nABE Fairview\nABE Makati\nABE Taft\nABE Cainta\nABE Pampanga\nABE Naga', 'Tuition varies depending on the program. Estimated range: ₱25,000 – ₱60,000 per semester. Offers installment plans and scholarships/discounts (in some cases).', 'No highly competitive national entrance exam. Admission is based on application and basic screening. Some programs may require interviews.', 'Accomplished Application Form\nGrade 12 Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID photos\nValid ID\nAfter acceptance:\nOriginal academic records\nMedical certificate (if required)\nEnrollment forms', 'Notice of Admission\nOriginal Form 138 / Transcript\nCertificate of Graduation\nGood Moral Certificate\nID photos\nValid ID', 'Address: Aurora Blvd., Cubao, Quezon City\nPhone: (02) 8913-3333\nEmail: inquire@abe.edu.ph\nWebsite: https://www.abe.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(110, 'Access Computer and Technical Colleges - Cubao', 'Private', 'Quezon City', 'A private educational institution in the Philippines that focuses on information technology, business, and technical-vocational education. ACT Colleges aims to provide affordable, skill-based, and industry-oriented training, producing graduates who are ready for employment in IT, business, and service industries.', 'ACT Recto\nACT Las Piñas\nACT Caloocan\nACT Fairview\nACT Cebu\nACT Iloilo', 'Tuition varies depending on the program. Generally affordable compared to major private universities. Offers installment plans and scholarships/discounts for selected students. Some programs are TESDA-aligned (lower cost).', 'No competitive national entrance exam. Admission is based on application submission and basic evaluation. Some programs may require interview or assessment.', 'Accomplished Application Form\nGrade 12 Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID photos\nValid ID\nAfter acceptance:\nOriginal academic records\nMedical certificate (if required)\nEnrollment forms', 'Notice of Admission\nOriginal Form 138 / Transcript\nCertificate of Graduation\nGood Moral Certificate\nID photos\nValid ID', 'Address: Aurora Blvd., Quezon City (Cubao Campus)\nPhone: (02) 8911-1717\nEmail: info@act.edu.ph\nWebsite: https://www.act.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59');
INSERT INTO `universities` (`id`, `name`, `type`, `location`, `description`, `campus_branches`, `tuition_fees`, `exam`, `requirements`, `enrollment_requirements`, `contact_links`, `created_at`, `updated_at`) VALUES
(111, 'ACLC College of Commonwealth', 'Private', 'Quezon City', 'A private college under the AMA Education System located in Quezon City. ACLC focuses on information technology, business, and office administration programs, providing affordable, skills-based, and industry-oriented education designed to prepare students for immediate employment.', 'ACLC Cubao\nACLC Fairview\nACLC Caloocan\nACLC Manila\nACLC Cebu', 'Tuition is affordable compared to major private universities. Estimated range: ₱20,000 – ₱50,000 per semester. Offers installment plans and scholarships/discounts.', 'No national entrance exam. Admission is based on application submission and basic evaluation. Some programs may require interviews.', 'Accomplished Application Form\nGrade 12 Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID photos\nValid ID\nAfter passing:\nOriginal academic records\nEnrollment forms\nMedical certificate (if required)', 'Notice of Admission\nOriginal Form 138 / Report Card\nCertificate of Graduation\nGood Moral Certificate\nID photos\nValid ID (for verification)', 'Address: Commonwealth Avenue, Quezon City\nWebsite: https://amaes.edu.ph', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(112, 'AMA Computer College - Fairview', 'Private', 'Quezon City', 'A private non-sectarian college and part of the AMA Education System, one of the pioneers of IT and computer education in the Philippines. Recognized for programs in Information Technology, Computer Science, Engineering, Business, Hospitality, and Digital Media. The Fairview Campus serves students from Quezon City, Fairview, Novaliches, and nearby areas.', 'AMA University Quezon City\nAMA Makati\nAMA Caloocan\nAMA Pasig\nAMA Davao\nAMA Cebu', 'Annual Estimate: ₱65,000 – ₱75,000 per year. Per Trimester Estimate: Around ₱22,000 – ₱30,000+ per term depending on units and course load.', 'Entrance exam requirements may vary by year/program. Some applicants may undergo screening or academic evaluation. Must be a Senior High School graduate from a recognized secondary school. Transferees accepted with previous college records.', 'Completed application form\nGrade 12 Report Card / Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID photos\nTranscript of Records (for transferees)\nOriginal academic credentials\nMedical clearance (if required)', 'Approved admission\nSubject enlistment\nTuition/down payment\nSubmission of complete records', 'Address: Lot 10 Blk. 83 Regalado Highway, Quezon City\nPhone: 289211115\nEmail: ama_fairview@amaes.edu.ph\nWebsite: http://www.ama.edu.ph/', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(113, 'AMA Computer University', 'Private', 'Quezon City', 'A private non-sectarian university and part of the AMA Education System, founded in 1980 by Dr. Amable R. Aguiluz V. Recognized as one of the pioneers of computer education in the Philippines, specializing in Information Technology, Computer Science, Engineering, Business, Hospitality, and emerging technology programs.', 'AMA University Quezon City (Main)\nAMA Makati\nAMA Caloocan\nAMA Pasig\nAMA Davao\nAMA Cebu', 'Annual Estimate: ₱65,000 – ₱75,000 per year. Per Trimester Estimate: Around ₱22,000 – ₱30,000+ per term depending on units and course load.', 'Admission may include screening, evaluation, or placement testing depending on campus/program. Some branches allow direct enrollment after document review. Must be a Senior High School graduate from a recognized secondary school. Transferees accepted with previous college records.', 'Completed application form\nGrade 12 Report Card / Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID photos\nTranscript of Records (for transferees)\nOriginal academic credentials\nMedical clearance (if required)', 'Approved admission\nSubject enlistment\nTuition/down payment\nSubmission of complete records', 'Website: http://www.ama.edu.ph/', '2026-05-09 16:18:59', '2026-05-09 16:18:59'),
(114, 'Eulogio \"Amang\" Rodriguez Institute of Science and Technology (EARIST)', 'SUC', 'Manila', 'A premier state college in Manila established in 1945, focusing on industrial technology, engineering, arts, and sciences. Offers affordable, quality vocational and technical education with a strong emphasis on producing globally competitive graduates.', 'EARIST Cavite', 'EARIST follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Some fees may still apply (miscellaneous, lab, etc.).', 'Take the EARIST College Admission Test (ECAT). The exam evaluates academic readiness and determines admission eligibility. Must be a Grade 12 student or Senior High School graduate with no failing grades. Some programs may require interviews or additional screening.', 'Accomplished Application Form (ECAT Form)\nSenior High School Report Card (Form 138) or Copy of Grades\nCertificate of Good Moral Character\nCertificate of Graduation or Certificate of Being a Graduating Student\nPSA Birth Certificate\nAfter passing ECAT:\nOriginal Report Card (Form 138)\nOriginal Certificate of Good Moral Character\nMedical Certificate (if required)\n2x2 ID pictures\nOther course-specific requirements', 'Notice of Admission / Proof of passing ECAT\nComplete set of submitted original documents\nCompleted enrollment form\nStudent ID processing\nAttendance in orientation (if required)', 'Address: Earist Nagtahan St., Sampaloc, Manila, Philippines, 1008\nEmail: earistofficial1945@gmail.com\nWebsite: https://earist.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(115, 'Philippine Normal University - Main', 'SUC', 'Manila', 'A public institution recognized as the National Center for Teacher Education in the Philippines. Established in 1901, it specializes in training future educators through various undergraduate programs in elementary, secondary, and specialized education fields.', 'PNU North Luzon\nPNU South Luzon\nPNU Visayas\nPNU Mindanao', 'PNU follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. For Master\'s, Doctorate, and International Students: approximately ₱20,000 per semester.', 'Take the Philippine Normal University Admission Test (PNUAT). Must be a Grade 12 student or Senior High School graduate. Must have no grade lower than 80% in major subjects (English, Math, Science). Must have a GWA of at least 85%. Must not have taken any college course (for freshmen applicants). PNU is highly selective and focuses on applicants with strong academic performance.', 'Certified True Copy of Report Card (Form 137/138) or latest grades\nCertification from school that applicant is graduating SHS student\n2 copies of recent 2x2 ID pictures\nCompleted application form (PNU online system)\nRecommendation letters (teacher/principal) if required\nAfter passing PNUAT:\nOriginal Report Card (Form 138)\nOriginal Certificate of Good Moral Character\nMedical clearance (if required)', 'Notice of admission / proof of passing PNUAT\nComplete original academic documents\nAccomplished enrollment forms\nID picture and student profile requirements\nAttendance in orientation (if required)', 'Address: Taft Avenue, Manila, Philippines\nPhone: +63 253171768\nEmail: socmed@pnu.edu.ph\nWebsite: pnu.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(116, 'Polytechnic University of the Philippines - Sta. Mesa, Manila', 'SUC', 'Manila', 'One of the largest state universities in the Philippines located in Sta. Mesa, Manila. Known for providing affordable and accessible education to thousands of students nationwide. PUP is often referred to as \"Sintang Paaralan\" and is recognized for producing skilled graduates in business, engineering, and public administration.', 'PUP Taguig\nPUP Caloocan\nPUP Quezon City\nPUP San Juan\nPUP Parañaque\nPUP Bataan\nPUP Bulacan (Sta. Maria, Pulilan)\nPUP Nueva Ecija\nPUP Quezon (Lopez, Mulanay, Unisan, General Luna)\nPUP Batangas (Sto. Tomas)\nPUP Cavite (Maragondon, Alfonso)\nPUP Laguna (Biñan, San Pedro, Sta. Rosa, Calauan)\nPUP Mindoro (Bansud, Sablayan)', 'PUP follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Around ₱1,600 per unit for undergraduate programs if not qualified under the Free Tuition Law. Master\'s: ₱2,250 per unit. Doctorate: ₱2,500 per unit.', 'Take the Polytechnic University of the Philippines College Entrance Test (PUPCET). Must be a Grade 12 student or Senior High School graduate. Must meet required academic performance standards. Must not have taken any college units (for freshmen). Admission is highly competitive. Some programs (e.g., engineering, accountancy) are quota courses.', 'Completed PUP Online Application Form (iApply system)\nSenior High School Report Card (Form 138)\nCertificate of Graduation or Proof of being a graduating student\nPSA Birth Certificate\n2x2 ID Picture\nAfter passing PUPCET:\nOriginal Report Card (Form 138)\nCertificate of Good Moral Character\nOther Program-Specific Requirements', 'Notice of Admission\nComplete Original Documents\nEnrollment form and student profile\nParticipation in Orientation', 'Address: Anonas St., Sta. Mesa, Manila, Philippines, 1016\nPhone: 0910 649 4049\nEmail: inquire@pup.edu.ph\nWebsite: https://www.pup.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(117, 'Technological University of the Philippines - Manila', 'SUC', 'Manila', 'A public state university located in Ermita, Manila, established in 1901 as a trade school. Specializes in technology, engineering, and industrial education. Known for producing highly skilled graduates in engineering and technical fields, making it one of the leading technological universities in the Philippines.', 'TUP Cavite (Rosario)\nTUP Lopez (Quezon Province)\nTUP Taguig\nTUP Visayas', 'TUP follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Some fees may still apply (miscellaneous, lab, etc.).', 'Take the Technological University of the Philippines Admission Test (TUPAT). Must be a Grade 12 student or Senior High School graduate. Must meet required academic standards. Must not have taken college units (for freshmen applicants). Admission can be competitive, especially for engineering programs. Some programs may require additional screening or interviews.', 'Completed application form (online or onsite)\nSenior High School Report Card (Form 138) or grades\nCertificate of Graduation or proof of graduating status\nPSA Birth Certificate\n2x2 ID picture\nAfter passing TUPAT:\nOriginal Report Card (Form 138)\nCertificate of Good Moral Character\nMedical clearance (if required)\nOther program-specific requirements', 'Notice of admission / passing TUPAT\nComplete original documents\nAccomplished enrollment forms\nParticipation in orientation', 'Address: Ayala Blvd. corner San Marcelino St. Ermita, Manila, Philippines\nPhone: (02) 301 3001\nEmail: uitc@tup.edu.ph\nWebsite: tup.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(118, 'University of the Philippines - Manila', 'SUC', 'Manila', 'A public state university located in Ermita, Manila, and one of the constituent universities of the UP System. Recognized as the country\'s premier institution for health sciences and medical education, producing top professionals in medicine, nursing, pharmacy, and public health. Affiliated with the Philippine General Hospital, the country\'s largest hospital.', 'UP Los Baños (Laguna)\nUP Diliman (Quezon City)\nUP Visayas\nUP Baguio\nUP Mindanao\nUP Cebu\nUP Open University (distance learning)', 'UP follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Some fees may still apply (miscellaneous, lab, etc.).', 'Take the UP College Admission Test (UPCAT), administered once a year (usually August). Scores are combined with high school grades to determine qualification. Must be graduating from Senior High School (Grade 12) or already a graduate. Must have complete grades from Grades 8–11. Must not have taken any college subjects yet. Must not have previously taken the UPCAT or applied to UP. Some colleges may require placement exams or interviews, and have limited slots.', 'Form 1 – Personal Data Sheet (online submission)\nForm 2B – High School Record (submitted by school)\nValid email address\nOfficial copies may be required for final verification\nAfter passing UPCAT:\nOfficial High School Transcript (original copy)\nPSA Birth Certificate (original + photocopy)\nMedical Certificate (UP Health Service/accredited clinic)\nStudent Directory / personal data forms\nPassport-size photos', 'Notice of Admission (NOA)\nOriginal Form 138 / Report Card (with eligibility for college)\nCertificate of Graduation (if not yet included in Form 138)\nUP Student Directory / Registration Forms\nMedical Clearance (from UP Health Service)\n2x2 or passport-size ID photos\nValid ID (for verification)\nEnrollment is done through UP\'s online system (CRS – Computerized Registration System)', 'Address: Padre Faura Corner Maria Orosa Street, Manila, Philippines\nEmail: upm-ippao@up.edu.ph\nWebsite: http://www.upm.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(119, 'Pamantasan ng Lungsod ng Maynila (PLM)', 'LUC', 'Manila', 'A public local university located in Intramuros, Manila, established in 1965 and funded by the City Government of Manila. Known for providing quality yet affordable education, especially for residents of Manila, and is recognized for strong programs in medicine, law, engineering, and social sciences.', 'PLM operates primarily as a single-campus university.', 'PLM follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Some fees may still apply (miscellaneous, lab, etc.).', 'Take the Pamantasang Lungsod ng Maynila Admission Test (PLMAT). Must be a Grade 12 student or Senior High School graduate. Must come from a recognized secondary school. Priority is given to residents of Manila. Admission is competitive, particularly for medicine and law. Some programs require interviews and additional screening.', 'Completed PLM online application form\nSenior High School Report Card (Form 138) or grades\nCertificate of Graduation or proof of graduating status\nPSA Birth Certificate\n2x2 ID picture\nAfter passing PLMAT:\nOriginal Report Card (Form 138)\nCertificate of Good Moral Character\nMedical Clearance (if required)\nAdditional documents depending on course requirement', 'Notice of admission (PLMAT result)\nComplete original documents\nEnrollment forms and student profile\nParticipation in orientation', 'Address: General Luna corner Muralla Streets, Intramuros, Manila, 1002 Metro Manila\nPhone: (02) 8 995-46-70\nEmail: ithelp@plm.edu.ph\nWebsite: http://plm.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(120, 'Universidad de Manila (UDM)', 'LUC', 'Manila', 'A public local university located in Ermita, Manila, established in 1995 and funded by the City Government of Manila. Aims to provide accessible and quality education especially for residents of Manila, offering programs in business, education, engineering, and social sciences.', 'UDM operates as a single-campus university.', 'UDM follows the Free Tuition Law (RA 10931) → most Filipino students pay ₱0 tuition. Some fees may still apply (miscellaneous, lab, etc.).', 'Take the Universidad de Manila Admission Test. Some admission periods may rely on academic evaluation instead of exams. Must be a Grade 12 student or Senior High School graduate. Priority is given to Manila residents. Some programs may have limited slots.', 'Completed application form\nSenior High School Report Card (Form 138) or grades\nCertificate of Graduation or proof of graduating status\nPSA Birth Certificate\n2x2 ID picture\nAfter passing:\nOriginal Report Card (Form 138)\nCertificate of Good Moral Character\nMedical clearance (if required)\nOther course-specific requirements', 'Notice of admission\nComplete original documents\nEnrollment forms and student profile\nParticipation in orientation', 'Address: 659-A Cecilia Muñoz St., 1000\nEmail: mgatdula@gmail.com\nWebsite: https://udmwebsite.udm.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(121, 'Dr. Jose Fabella Memorial Hospital School of Midwifery', 'OGS', 'Manila', 'A government-run training institution located in Sta. Cruz, Manila, operating under the Dr. Jose Fabella Memorial Hospital. Specializes in midwifery education, training students to become skilled midwives who assist in childbirth and provide maternal care.', 'Located within the hospital premises, allowing students to gain hands-on clinical experience.', 'Funded by the government – follows the Free Tuition Law (RA 10931). Some batches may receive allowances or support. Some fees may still apply (miscellaneous, lab, etc.).', 'Must follow a Screening Process upon Application. Applicants may be required to take an entrance exam and/or screening including interview and evaluation. Must be a Senior High School graduate, preferably from STEM or health-related strands. Must be physically and mentally fit. Must show interest in healthcare and maternal services.', 'Completed application form\nHandwritten Application Letter\nPersonal Data Sheet (PDS)\nSenior High School Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\nMedical certificate', 'Submit complete original documents\nComply with hospital training requirements', 'Address: 4th Floor, Dr. Jose Fabella Memorial Hospital, San Lazaro Compound, Tayuman St. Sta. Cruz, Manila, Philippines, 1014\nPhone: 0968 659 6651\nEmail: som@fabella.doh.gov.ph\nWebsite: https://fabella.doh.gov.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(122, 'Adamson University', 'Private', 'Manila', 'A private Catholic (Vincentian) university located in Manila, founded in 1932 as the Adamson School of Industrial Chemistry and became a university in 1941. Known for strong programs in engineering, pharmacy, nursing, business, and law.', 'Adamson University has only one main campus.', 'Estimated range: ₱20,000 – ₱120,000 per semester depending on the program. Offers installment plans and scholarships/discounts.', 'Applicants may be required to take an entrance exam and/or screening. May also include interview and evaluation. Must be a Senior High School graduate. Open to students nationwide (not limited to Manila residents).', 'Completed application form\nSenior High School Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\nMedical certificate\nOriginal academic records', 'Notice of acceptance\nComplete original documents\nCompliance with enrollment requirements\nOffers scholarships and financial assistance', 'Address: 900 San Marcelino Street, Ermita, Manila, NCR, Philippines\nEmail: admission@adamson.edu.ph\nWebsite: https://www.adamson.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(124, 'Arellano University - Manila', 'Private', 'Manila', 'A private, coeducational, and non-sectarian university founded in 1938 by Florentino Cayco, Sr. as a law school, later expanded into a full university offering various undergraduate and graduate programs.', 'Juan Sumulong Campus (Main – Manila)\nJose Abad Santos Campus (Pasay)\nApolinario Mabini Campus (Pasay – School of Law)\nAndres Bonifacio Campus (Pasig)\nJose Rizal Campus (Malabon)\nElisa Esguerra Campus (Malabon)\nPlaridel Campus (Mandaluyong)', 'Commonly ranges from ₱25,000 – ₱70,000+ per semester depending on course and units. Offers scholarships, discounts, and academic honors incentives.', 'Admission may require an entrance examination or academic evaluation. Some programs may include interviews or additional screening. Must be a Senior High School graduate from a recognized school.', 'Completed application form\nSenior High School Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID pictures\nAfter acceptance:\nOriginal credentials\nMedical certificate (if required)\nProgram-specific requirements', 'Notice of acceptance\nComplete original documents\nEnrollment forms\nOrientation attendance', 'Address: 2600 Legarda Street, Sampaloc, Manila, Philippines\nEmail: info@arellano.edu.ph\nWebsite: https://www.arellano.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(125, 'Centro Escolar University - Manila', 'Private', 'Manila', 'A private non-sectarian university established in 1907 by Librada Avelino and Carmen de Luna. One of the oldest private universities in the Philippines with its historic main campus in Mendiola, San Miguel, Manila. Especially recognized for strong programs in dentistry, pharmacy, optometry, medical technology, business, and education.', 'Centro Escolar University (Makati)\nCentro Escolar University (Malolos)\nCentro Escolar University (Las Piñas)', 'Around ₱35,000 – ₱90,000+ per semester depending on course and laboratory fees. Offers scholarships, academic grants, and discounts for qualified students.', 'Admission may require an entrance examination or academic evaluation. Some programs may require interviews or aptitude tests. Must be a Grade 12 graduate from a recognized secondary school. Known for strong board exam performance in several health science programs.', 'Completed application form\nSenior High School Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID pictures\nAfter passing:\nOriginal academic credentials\nMedical clearance (if required)\nProgram-specific requirements', 'Notice of acceptance\nComplete original documents\nEnrollment forms\nOrientation attendance', 'Address: 9 Mendiola Street, San Miguel, Manila City\nPhone: (02) 8735-6861 to 71 or (02) 8735-6860\nEmail: ceuadmission@ceu.edu.ph\nWebsite: https://www.ceu.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(126, 'Chinese General Hospital Colleges', 'Private', 'Manila', 'A private non-sectarian educational institution located in Santa Cruz, Manila, established in 1921 as the Chinese General Hospital School of Nursing. Later expanded into a full college affiliated with the Chinese General Hospital and Medical Center, one of the oldest hospitals in the Philippines.', 'CGHC primarily operates as a single-campus institution integrated with hospital facilities.', 'Varies depending on program, around ₱25,000 – ₱60,000. Health science courses with laboratories/clinical training usually cost more.', 'Applicants are commonly required to take the Chinese General Hospital Colleges Entrance Examination (CGHCEE). Must be a Senior High School graduate from a recognized secondary school. Must meet program-specific academic standards.', 'Completed application form\nSenior High School Report Card / grades\nPSA Birth Certificate\nValid ID\nID pictures\nPayment of application fee (if applicable)\nAfter acceptance:\nOriginal Report Card / Transcript of Records\nCertificate of Good Moral Character\nMedical clearance (if required)\nOther program-specific requirements', 'Notice of acceptance\nComplete original documents\nEnrollment forms\nTuition/down payment settlement', 'Address: 286 Blumentritt Street, Sta. Cruz, Manila, Philippines, 1014\nEmail: admissions@cghc.edu.ph\nWebsite: https://www.cghc.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(127, 'Colegio de San Juan de Letran', 'Private', 'Manila', 'A private Catholic educational institution in Intramuros, Manila, founded in 1620 and operated by the Order of Preachers. One of the oldest colleges in the Philippines. Known for strong programs in business, accountancy, engineering, communication, psychology, education, and law, as well as its historic legacy and Dominican values formation.', 'Colegio de San Juan de Letran Calamba\nColegio de San Juan de Letran Bataan\nColegio de San Juan de Letran Manaoag', 'Around ₱65,000+ average depending on program and semester load. Offers Rector\'s Scholarship, Academic Scholarships, Student Assistantship, and external scholarships (CHED, DOST, etc.).', 'Applicants may take the LETPASS / entrance screening process depending on the program and academic year. Some admissions cycles may focus on academic evaluation. Must be a Senior High School graduate from a recognized secondary school.', 'Completed online application form\n2x2 recent ID picture\nPhotocopy of latest school ID\nGrade 11 report card (for incoming freshmen)\nCertified True Copy of Grades (for transferees)\nAfter acceptance:\nOriginal Report Card / Transcript of Records\nCertificate of Good Moral Character\nPSA Birth Certificate\nBaptismal Certificate (may be requested)\nProgram-specific requirements', 'Notice of acceptance\nComplete original documents\nReservation / processing fee\nSubject enlistment and payment of assessed fees\nOrientation attendance', 'Address: 151 Muralla St., Manila, Philippines, 1002\nPhone: (02) 527 7693\nEmail: publicaffairs@letran.edu.ph\nWebsite: https://www.letran.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(128, 'De La Salle University - Manila', 'Private', 'Manila', 'A private Catholic Lasallian university located in Taft Avenue, Malate, Manila, established in 1911 by the Brothers of the Christian Schools. Consistently recognized as one of the top universities in the Philippines, known for excellence in business, engineering, computer studies, sciences, economics, education, and liberal arts.', 'De La Salle University Laguna Campus\nDe La Salle University Rufino Campus', 'Commonly ranges from ₱80,000 – ₱120,000+ per term depending on program and units. DLSU commonly uses a trimester system for many programs. Offers scholarships, grants, student assistantships, and external scholarships.', 'Freshman applicants usually apply through the DLSU College Admission process. May include an entrance exam or academic evaluation depending on current policy cycle. Must be a Senior High School graduate from a recognized secondary school. Must meet competitive academic standards. Admission is competitive. Some degree programs may have quota slots or special screening.', 'Completed online application form\nGrade 11 / Grade 12 records\nRecommendation forms (if required)\nPSA Birth Certificate\nID photo\nApplication fee payment\nAfter passing:\nOriginal Report Card / credentials\nCertificate of Good Moral Character\nOther program-specific requirements', 'Notice of admission\nConfirmation fee\nComplete original documents\nEnrollment and subject enlistment\nOrientation participation', 'Address: De La Salle University, 2401 Taft Avenue, Manila, 0922 Philippines\nPhone: (632) 8524-4611 / (632) 8526-4242\nWebsite: https://www.dlsu.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(129, 'De La Salle - College of Saint Benilde', 'Private', 'Manila', 'A private Catholic Lasallian institution located in Malate, Manila, founded in 1988 and part of the De La Salle Philippines system. Widely known for innovative and industry-focused programs in arts, design, hospitality, business, technology, deaf education, and diplomacy. Especially recognized for creative programs such as multimedia arts, animation, fashion design, and music production.', 'Benilde School of Design and Arts\nAngelo King International Center\nBenilde Antipolo', 'Average estimated tuition is around ₱195,000 per year depending on the program. Offers scholarships, grants, and student assistance programs.', 'Freshman admission is through the Benilde college admissions process. May include academic evaluation or entrance screening depending on the intake cycle. Must be a Senior High School graduate from a recognized secondary school. Some creative programs require portfolios or auditions. Industry immersion and internships are emphasized.', 'Completed online application form\nGrade 11 / Grade 12 records\nID photo\nPSA Birth Certificate (if required)\nApplication fee payment\nPortfolio / audition for some arts programs\nAfter passing:\nOriginal Report Card / credentials\nGood Moral Certificate\nProgram-specific requirements\nMedical forms (if required)', 'Notice of admission\nConfirmation fee\nComplete original documents\nSubject enlistment / enrollment process\nOrientation participation', 'Address: 2544 Taft Avenue, Manila, Philippines, 1004\nPhone: 282305100\nEmail: admissions@benilde.edu.ph\nWebsite: http://www.benilde.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(130, 'Emilio Aguinaldo College', 'Private', 'Manila', 'A private non-sectarian coeducational institution founded in 1957. Known for strong programs in health sciences, medicine, dentistry, business, education, criminology, hospitality, and information technology. Has a teaching hospital partnership that supports hands-on learning for healthcare students.', 'Emilio Aguinaldo College Cavite – Dasmariñas, Cavite', 'Around ₱40,000 – ₱80,000+ per semester depending on course and laboratory fees. Health science programs may cost more. Offers scholarships, discounts, and installment options.', 'Admission may include an entrance examination or academic screening depending on the applicant category and current policy. Must be a Senior High School graduate from a recognized secondary school.', 'Completed application form\nLetter of Intent\nSenior High School Report Card / Transcript\nPSA Birth Certificate\nGood Moral Certificate\nID pictures\nApplication fee\nAfter passing:\nOriginal academic credentials\nMedical clearance (for some programs)\nProgram-specific requirements', 'Notice of admission\nComplete original documents\nEnrollment forms\nTuition/down payment settlement', 'Address: 1113-1117 San Marcelino St., Paco, Manila, Philippines, 1007\nPhone: 285212710\nWebsite: https://www.eac.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(131, 'Far Eastern University - Manila', 'Private', 'Manila', 'A private non-sectarian university located in Sampaloc, Manila, founded in 1928 by Nicanor Reyes Sr. and officially became a university in 1934. One of the most established institutions in the Philippines, well known for its heritage campus in the University Belt. Recognized for strong programs in business, accountancy, nursing, medical technology, psychology, architecture, education, and the arts.', 'FEU Makati\nFEU Alabang\nFEU Diliman\nFEU Roosevelt\nFEU Institute of Technology\nFEU Dr. Nicanor Reyes Medical Foundation', 'Many programs range around ₱40,000 – ₱80,000+ per semester. Offers academic scholarships, grants, installment plans, and financial aid programs.', 'Freshman applicants usually take the FEUCAT (Far Eastern University College Admission Test) or equivalent admission screening. Some admission cycles may use academic evaluation. Must be a Senior High School graduate from a recognized secondary school. Application fee around ₱500.', 'Grade 12 Report Card\nCertificate of Good Moral Character\nPSA Birth Certificate\nCertificate of Graduation / Diploma copy\nCompleted application form\nApplication fee (around ₱500)\nAfter passing:\nOriginal academic credentials\nProgram-specific requirements\nMedical clearance (if required)', 'Notice of admission\nComplete original documents\nPayment of fees / reservation\nSubject enlistment and enrollment confirmation', 'Address: Nicanor Reyes Street, Sampaloc, Manila, Philippines, 1108\nPhone: 287777338\nEmail: marketing@feu.edu.ph\nWebsite: http://www.feu.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(132, 'FEATI University', 'Private', 'Manila', 'A private non-sectarian coeducational university located in Santa Cruz, Manila, founded in 1946. Formerly known as the Far Eastern Aeronautics School, originally specializing in aviation education and later expanded into engineering, maritime, business, architecture, and other professional programs.', 'FEATI primarily operates as a single-campus university in Manila.', '₱40,000 – ₱60,000+ per semester for many programs. Specialized engineering/aviation programs may be higher. Offers scholarships and installment/payment options.', 'Freshman applicants are commonly required to take the FEATI College Admission Test (FCAT). Published fee: ₱300. Must be a Senior High School graduate or graduating Grade 12 student from a recognized secondary school.', 'Completed application form\nForm 138 / High School Report Card\nCertificate of Good Moral Character\nBirth Certificate copy\n2x2 ID pictures (3 pieces)\nAfter acceptance:\nOriginal academic credentials\nEnrollment forms\nProgram-specific requirements\nMedical clearance (if required)', 'Notice of acceptance\nComplete original documents\nTuition/down payment settlement\nSubject enlistment and registration', 'Address: Helios St. cor. C. Palanca Sr., Sta. Cruz, Manila City, Philippines, 1003\nEmail: university.secretariat@featiu.edu.ph\nWebsite: http://www.featiu.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(133, 'La Consolacion College - Manila', 'Private', 'Manila', 'A private Catholic educational institution in Mendiola, San Miguel, Manila, founded in 1902 by the Augustinian Sisters of Our Lady of Consolation. One of the oldest Catholic schools in Manila. Known for programs in nursing, business, education, psychology, tourism, information technology, and music. Emphasizes academic excellence, Christian values, and community service.', 'La Consolacion University Philippines (Bulacan)\nLa Consolacion College Bacolod\nLa Consolacion College Novaliches-Caloocan\nLa Consolacion College Binan\nLa Consolacion College Daet\nLa Consolacion College Iriga\nLa Consolacion College Pasig\nLa Consolacion College Valenzuela', 'Average tuition fee: ₱38,000 – ₱66,000 per semester depending on the program. Reservation of slots: ₱1,500 per slot. Scholarship opportunities ranging from 50% to 100% discount.', 'No entrance exams for incoming freshmen. Must be a Grade 12 graduate from a recognized secondary school.', 'Original Copy of Report Card (Form 138)\nOriginal Copy of Certificate of Good Moral Character\nOriginal and Photocopy of PSA Birth Certificate\nOriginal and Photocopy of Baptismal Certificate\n2 pcs 2x2 Picture in White Background\n1 Long Brown Envelope', 'Submit complete requirements at the Registrar\'s office\nPay required downpayment', 'Address: 8 Mendiola, Manila, 1005 Metro Manila\nPhone: 5310-0514 loc 150\nEmail: admissions@lccm.edu.ph\nWebsite: https://www.lccm.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(134, 'Lyceum of the Philippines University - Manila', 'Private', 'Manila', 'A private non-sectarian university in Intramuros, Manila, founded in 1952 by José P. Laurel. Especially recognized for excellence in hospitality management, tourism, customs administration, business, international relations, psychology, and communication. Known for global industry linkages and career-oriented programs.', 'Lyceum of the Philippines University Batangas\nLyceum of the Philippines University Cavite\nLyceum of the Philippines University Laguna', 'Estimated average tuition: ₱80,000 – ₱120,000 per year depending on the program. Reservation fee for slots: around ₱2,000. Offers scholarships, grants, and financial assistance.', 'Applicants may be required to take the LPU College Entrance Test (OLCET / admission screening) depending on policy for the academic year. Must be an SHS Graduating student. Preferably belongs to the top 10% of the graduating batch of at least 35 students or is a graduate from a Science High School. With at least 90% GWA. Must be of good moral character and a Filipino citizen.', 'Original & Photocopy of Documents:\nGr 12 Report Card (F138)\nGood Moral Certificate\nOriginal PSA Birth Certificate\nPhotocopy of Valid ID of Guardian if minor\n1 pc. 2x2 ID Photo in white background', 'Notice of admission\nComplete original documents\nReservation / confirmation fee\nEnrollment and subject registration', 'Address: Muralla Cor. Real Sts., Intramuros, 1002 Manila, Philippines\nPhone: (632) 8527-8253 to 56\nEmail: admission.mnl@lpu.edu.ph\nWebsite: https://manila.lpu.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(135, 'Mapúa University - Manila', 'Private', 'Manila', 'A private non-sectarian university in Intramuros, Manila, founded in 1925 by Tomas Mapúa, the first registered Filipino architect. One of the most respected universities in the Philippines, especially known for excellence in engineering, architecture, information technology, business, media studies, and sciences. Highly recognized for producing top board exam passers and industry-ready graduates.', 'Mapúa University Makati\nMapúa Malayan Colleges Laguna\nMapúa Malayan Colleges Mindanao', 'Many students report ₱50,000 – ₱80,000+ per term/semester equivalent depending on course and units. Installment Options: 40% downpayment / 30% midterm / 30% finals.', 'Freshman applicants usually take the MPASS (Mapúa Program Placement Assessment). Must be a Grade 12 student or Senior High School graduate. Must not yet be enrolled in another college as freshman applicant. Must come from a recognized secondary school. Reservation fee: ₱5,000 (non-refundable/non-transferable).', 'Completed online application form\nLRN\nGrade 11 grades (Math, Science, English often requested)\nEmail and contact details\nSenior High School information\nAfter passing:\nOriginal Report Card / credentials\nBirth Certificate\nGood Moral Certificate\nOther program-specific requirements', 'Reservation fee: ₱5,000 (non-refundable)\nFinal subject schedule\nPayment of tuition/down payment\nCompletion of enrollment process', 'Address: 658 Muralla St., Intramuros, Manila 1002, Philippines\nPhone: +63(2) 8247-5000\nWebsite: https://www.mapua.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(136, 'The National Teachers College', 'Private', 'Manila', 'A private non-sectarian educational institution located in Quiapo, Manila, founded in 1928 as the first private teacher-training college in the Philippines. Originally established to develop professional educators, has since expanded into programs in business, criminology, psychology, information technology, tourism, and graduate studies.', 'NTC mainly operates as a single-campus institution in Manila.', '₱690 per unit basic tuition. ₱6,180 fixed miscellaneous fee per semester. ₱65 per unit variable miscellaneous fee. Sample: 18 units = ₱19,149.00 per semester. Installment option: 10% down payment, remaining balance payable monthly.', 'NTC follows an open admission policy. Applicants may apply directly through the Admissions Office or online application system. Screening and evaluation may still apply depending on the program. Transferees are also accepted with prior college records.', 'PSA Birth Certificate\nReport Card (for freshmen)\nTranscript of Records or Copy of Grades (for transferees)\nCompleted application form\nAfter acceptance:\nOriginal academic credentials\nGood Moral Certificate\nProgram-specific requirements (if needed)', 'Approved application\nPayment of down payment or full tuition\nSubmission of complete original records\nFinal registration / subject enlistment', 'Address: 629 J. Nepomuceno Street, Quiapo, Manila, Philippines, 1001\nPhone: 8734-5601\nEmail: support@ntc.edu.ph\nWebsite: https://ntc.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(137, 'National University - Manila', 'Private', 'Manila', 'A private non-sectarian university located in Sampaloc, Manila, founded in 1900. One of the oldest private universities in the country and the flagship campus of the National University Philippines system. Known for strong programs in allied health, engineering, business, architecture, information technology, education, psychology, and hospitality management. Also widely recognized for athletics through the UAAP.', 'NU MOA\nNU Fairview\nNU Baliwag\nNU Laguna\nNU Clark\nNU Dasmariñas\nNU East Ortigas', '₱20,000 – ₱45,000 per term depending on course and units. Since NU often uses a trisem system, yearly total may be around ₱60,000 – ₱135,000+ per year. Offers academic scholarships, athlete scholarships, discounts for honors graduates, and installment payment options.', 'NU commonly uses an admission screening / online application process. Some applicants may be admitted through academic evaluation instead of a traditional entrance exam. Must be a Senior High School graduate from a recognized secondary school.', 'Completed online application form\nGrade 12 Report Card / Form 138\nPSA Birth Certificate\nGood Moral Certificate\n2x2 ID photo\nOther documents if transferee or foreign applicant\nAfter acceptance:\nOriginal academic credentials\nMedical forms (if required)\nProgram-specific requirements', 'Admission approval\nSubject enlistment\nPayment of tuition/down payment\nSubmission of original credentials', 'Address: 551 M.F. Jhocson St. Sampaloc, Manila, PH 1008\nPhone: +632 8712-1900\nEmail: corpmarketingcomm@national-u.edu.ph\nWebsite: https://www.national-u.edu.ph/nu-manila/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(138, 'Perpetual Help College of Manila', 'Private', 'Manila', 'A private non-sectarian educational institution located in Sampaloc, Manila, founded in 1968 under the University of Perpetual Help System JONELTA. Known for programs in nursing, physical therapy, radiologic technology, business, communication, computer studies, tourism, and hospitality management.', 'PHCM mainly operates as a single-campus college in Manila.', 'Annual estimation ₱42,000 – ₱60,000 per year.', 'Must pass the Entrance Examination administered by the school. Must pass the initial interview conducted by the Admissions Department. Must be physically fit with a pleasant disposition. Must not have been subjected to any disciplinary action in previous school. Must be at least 5 feet in height (College of Nursing applicants).', 'Fill Out Application Form for College\nTake the Entrance Examination administered by the Guidance Department\nFill out a 201 Form and secure a Locator Number\nWait for release of examination results\nSubmit all requirements to respective colleges\nForm 138 (For Freshman applicants only) – 2 Photocopies\nCertificate of Good Moral Character – 2 Photocopies\nBirth Certificate (from NSO) – 2 Photocopies\nTwo (2) pieces – 2x2 ID Pictures', 'Submit all original credentials\nChest X-ray Result (Nursing, Physical Therapy, Occupational Therapy and Respiratory Applicants)\nHepa-B Screening Result for Nursing, Physical Therapy/Occupational Therapy/Respiratory Therapy and Hospitality Management applicants\nTwo (2) pieces – Long Brown Envelope\nTwo (2) pieces – Long Plastic Envelope\nOne (1) piece – Long Folder\nFully accomplished Student Personal Information Sheet (SPIS)', 'Address: 1240 V Concepcion St., Sampaloc, Manila, Philippines, 1008\nPhone: (+632) 8731-8199\nEmail: sdo.manila@uphsl.edu.ph\nWebsite: https://manila.uphsl.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(139, 'Philippine Christian University', 'Private', 'Manila', 'A private Christian university located in Malate, Manila, founded in 1946. Recognized for integrating academic excellence with Christian values, offering programs in business, education, nursing, criminology, information technology, tourism, psychology, and graduate studies.', 'PCU Dasmariñas, Cavite\nPCU Mary Johnston College of Nursing (Tondo, Manila)', 'Around ₱40,000 per year on average. Approximately ₱20,000 – ₱35,000 per semester depending on course and units.', 'PCU commonly uses an admission screening / evaluation process. Entrance exam requirements may vary depending on program and academic year. Must be a Senior High School graduate from a recognized secondary school.', 'Form 138 / Report Card\nCertificate of Good Moral Character\nTwo (2) copies of 2x2 picture\nAfter acceptance:\nOriginal academic credentials\nPSA Birth Certificate\nProgram-specific requirements\nMedical forms if required', 'Approved admission application\nTuition/down payment settlement\nSubject registration\nSubmission of original records', 'Address: 1648 Taft Avenue corner Pedro Gil St., Malate, Manila\nPhone: 282485370\nEmail: admissions.manila@pcu.edu.ph\nWebsite: https://pcu.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(140, 'Philippine College of Criminology (PCCR)', 'Private', 'Manila', 'A private non-sectarian college located in Sta. Cruz / Quiapo area, Manila, founded in 1954 by former Supreme Court Justice Felix Angelo Bautista. Recognized as one of the pioneer schools of criminology in the Philippines. Known for specializing in criminology, criminal justice, forensic studies, psychology, political science, and related programs.', 'PCCR mainly operates as a single-campus institution in Manila.', 'Various estimates suggest around ₱25,000 – ₱40,000 per year for some programs.', 'Some school listing sources indicate no regular entrance exam, with admission based on document screening/evaluation. Must be a Senior High School graduate for freshmen from a recognized secondary school. Transferees may apply with previous college records.', 'Completed application form\nGrade 12 Report Card / Form 138\nPSA Birth Certificate\nGood Moral Certificate\nID photos\nTranscript of Records (for transferees)\nAfter acceptance:\nOriginal academic credentials\nMedical clearance (if required)\nProgram-specific requirements', 'Approved admission application\nSubject registration\nPayment of tuition/down payment\nSubmission of complete credentials', 'Address: 641 Sales Street, Sta. Cruz, Manila, Philippines, 1003\nWebsite: http://www.pccr.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(141, 'Philippine School of Business Administration - Manila', 'Private', 'Manila', 'A private, specialized business school founded in 1963. Started as a training center for accountants and grew into one of the most respected business colleges in the Philippines. Famous for being a \"CPA Factory\" because of its high board exam passing rate.', 'PSBA Quezon City', 'Estimated Total per Semester: ₱20,000 – ₱30,000 depending on the number of units. Entrance Fee: ₱300. Academic Scholarships: Discounts available for students who graduated as Valedictorian or Salutatorian in Senior High School.', 'All new students must pass the school\'s Entrance Examination (fee approximately ₱300). A short talk with the Dean or Admissions Officer may be required. Must be a Senior High School graduate from a recognized secondary school.', '1x1 and 2x2 ID Pictures: 2 to 4 copies (white background with name tag)\nPSA Birth Certificate: 2 photocopies (bring original for verification)\nCertificate of Good Moral Character: Original copy\nForm 138 (High School Report Card): Original and photocopy\nForm 137 (Permanent Record): Often required for final processing', 'Notice of Acceptance: Issued after passing the exam and interview\nComplete Original Credentials: Surrender of original SHS documents\nPayment: Required downpayment or full tuition fee', 'Address: 826 R. Papa, Sampaloc, Manila, 1008 Metro Manila\nEmail: admissions@psba.edu\nTelephone: 5310-0040 | 0917-1917722\nWebsite: https://www.psba.edu/en/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(142, 'The Philippine Women\'s University - Manila', 'Private', 'Manila', 'Founded in 1919, a private, non-sectarian university famous for being the first university for women in Asia (it opened to men later). Highly respected for its programs in Music, Fine Arts, Nursing, and Social Work. Focuses on \"holistic education\" caring about character and creativity as much as grades.', 'Main Campus: 1743 Taft Avenue, Malate, Manila\nPWU Lucena\nPWU Fairview', 'Estimated Total per Semester: ₱45,000 – ₱60,000. Annual Total: approximately ₱90,000 – ₱120,000. Honor Students: 100% tuition discount for Highest Honors (98-100 GWA) and 50% for High Honors (95-97 GWA). Alumni Discount: 10% for children or grandchildren of PWU graduates. Family Income Subsidy: 100% tuition subsidy for students whose family income is below ₱300,000/year.', 'Entrance Exam / Assessment with ongoing schedule. Fee: approximately ₱300 – ₱500. Successful interview with the Dean or Department Chair required for specific courses. Must be a Senior High School graduate from a recognized school. Art Test for BFA or BS Interior Design applicants. Video Audition for Bachelor of Music applicants.', 'Completed Application Form\n1x1 and 2x2 ID Pictures (white background)\nPhotocopy of PSA Birth Certificate\nPhotocopy of Grade 12 Report Card (Form 138) or Transcript of Records\nHigh School Card Form 138 (original and photocopy)\nLetter of Recommendation / Good Moral Certificate from High School Principal / Guidance Counselor\nPSA certified birth certificate (1 photocopy)\nTwo (2) colored 1.5\" x 1.5\" ID pictures', 'Medical Clearance: A basic physical exam from the PWU clinic\nReservation Fee: Usually ₱5,000 to lock in your slot\nEnrollment Form: Completed through the PWU online portal', 'ISDN: +63(2) 8465-1765 | +63(2) 8465-1767 | +63(2) 8465-1777\nMobile: +63 956 675 4232 | +63 949 577 3828\nEmail: admissions@pwu.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23');
INSERT INTO `universities` (`id`, `name`, `type`, `location`, `description`, `campus_branches`, `tuition_fees`, `exam`, `requirements`, `enrollment_requirements`, `contact_links`, `created_at`, `updated_at`) VALUES
(143, 'St. Jude College', 'Private', 'Manila', 'Founded in 1968, part of the PHINMA Education system which uses modern, active learning methods designed to help students pass board exams and get hired quickly. Best known for \"Board Topnotchers\" in Nursing and Healthcare, but has expanded into Criminology, Business, and Technology.', 'SJC Quezon City\nSJC Cavite', 'Estimated Total per Semester: ₱25,000 – ₱35,000. Hawak Kamay Scholarship: 50% discount on tuition and miscellaneous fees for 4 years for qualified incoming freshmen. PHINMA Scholarship: Full 100% scholarship plus monthly allowance. Early Bird enrollment discounts available.', 'Entrance Exam ongoing (Daily schedules available from Monday to Saturday). Fee: Typically Free or very low processing fee. Must be a Senior High School graduate from a recognized school. Must pass the initial interview with the guidance counselor or dean.', '1x1 and 2x2 ID Pictures (2 copies each)\nOriginal Copy of Transcript of Records / Form 137\nPhotocopy of PSA Birth Certificate\nGood Moral Certificate from previous school\nAccomplished Application Form\nSenior High School Report Card (Form 138)', 'Notice of Acceptance (issued by the school)\nComplete original credentials (SHS Report Card/Form 138)\nSigned Enrollment Forms\nPayment of initial downpayment or tuition fee', 'Address: Dimasalang cor. Don Quijote St., Sampaloc, Metro Manila\nPhone: 0960-483-6786\nEmail: info.sjc@phinmaed.com\nWebsite: https://sjc.phinma.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(144, 'San Beda University', 'Private', 'Manila', 'A private, Benedictine institution founded in 1901. Famous for its Mendiola campus and for producing some of the country\'s most powerful leaders, including Philippine Presidents and Supreme Court Justices. Students are expected to follow the core values of Prayer, Study, and Service.', 'San Beda College Alabang', 'Estimated Total per Semester: ₱60,000 – ₱80,000. Annual Total: approximately ₱120,000 – ₱160,000. Entrance Scholarships: Full or partial tuition waivers for SHS Valedictorians and Salutatorians. Sibling Discount and Athletic/Artistic Grants available.', 'Entrance examination required. Exam dates vary by college department (College of Accountancy and Business: May 20, May 27, June 10, 2026; Other programs: multiple dates from May to July 2026). Fee: approximately ₱600 – ₱1,000. Must have a General Average of at least 82% with no failing grades. Must have a clean disciplinary record from Senior High School.', 'Application Form\nReport Cards\nPSA Birth Certificate (Photocopy)\nGood Moral Character Certificate\n2x2 colored photo with a white background', 'Original Report Card (Form 138): Showing \"Graduated\" status and LRN\nOriginal PSA Birth Certificate\nOriginal Good Moral Certificate\nMedical Clearance from the San Beda school clinic\nNotice of Admission (NAS)', 'Address: 638 Mendiola St., San Miguel, Manila, 1005 Metro Manila\nPhone: (+63)8726-2332\nWebsite: https://www.sanbeda.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(145, 'Technological Institute of the Philippines - Manila', 'Private', 'Manila', 'A premier private, non-sectarian engineering school in the heart of the University Belt. World-famous for its ABET accreditation, which is the \"Gold Standard\" in engineering and computing, meaning its degrees are recognized and respected in the USA and globally.', 'TIP Quezon City', 'Estimated Total per Semester: ₱35,000 – ₱50,000. Annual Total: approximately ₱70,000 – ₱100,000. Entrance Scholarships: Full or partial tuition discounts for SHS graduates with High Honors or Honors. Academic Scholarships for current students who maintain a high GWA.', 'Testing and interviews are ongoing for the August 2026 intake (started as early as January 2026). Only freshmen applicants with a GWA between 75% and 79% are required to take the exam. Those with a GWA of 80% or higher usually skip the exam but must complete a mandatory Guidance Interview. Must be a Senior High School graduate from a recognized school.', 'Online Application via T.I.P. Admission Portal\n2x2 ID Pictures with white background\nOriginal PSA Birth Certificate\nAfter acceptance:\nOriginal Grade 12 Report Card (Form 138/SF9)\nCertificate of Good Moral Character with school seal\nCertificate of Honors/Rank (for scholarship evaluation)', 'Original Grade 12 Report Card\nOriginal PSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID Photos\nPayment', 'Landline: (+632) 8733-9117\nEmail: admissions.manila@tip.edu.ph\nWebsite: www.tip.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(146, 'The University of Manila (UM)', 'Private', 'Manila', 'Founded in 1913 (originally as Instituto de Manila). A private, non-sectarian school famous for its slogan \"Patria, Scientia, et Virtus\" (Country, Science, and Virtue). Known for producing many of the country\'s past leaders including Vice Presidents and lawmakers.', 'One and only campus in Sampaloc Manila', 'Estimated Total per Semester: ₱20,000 – ₱30,000. Annual Total: approximately ₱40,000 – ₱60,000. Honor Students: Significant tuition discounts for SHS Valedictorians and Salutatorians. Full Payment and Sibling Discount available.', 'Must pass the entrance examination and meet the cut-off score for the chosen course. Exam fee must be paid at the Accounting Office before taking the test. Must be a Senior High School graduate or holder of a Philippine Educational Placement Test (PEPT) certificate. Must have a clean record and a certificate of good moral character.', 'Accomplished Application Form\nTwo (2) copies of recent 2x2 ID pictures (white background)\nOriginal and photocopy of the Grade 12 Report Card (Form 138)\nOriginal and photocopy of the PSA Birth Certificate\nOriginal Certificate of Good Moral Character\nAfter acceptance:\nOriginal Form 138 (your official Senior High School Report Card)\nGood Moral Certificate\nWritten Undertaking signed by student or parent', 'Notice of Admission\nComplete original credentials\nPayment', 'Address: 546 Mariano V. delos Santos Street, Sampaloc Manila, Philippines 1008\nTelephone: 8735-5085\nEmail: umnla.edu.ph@gmail.com\nWebsite: http://www.um.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(147, 'University of Santo Tomas (UST)', 'Private', 'Manila', 'Founded in 1611, UST is the only university in the world visited by three Popes. A private, Catholic school that balances traditional values with modern, high-tech education. Famously called the \"Catholic University of the Philippines\" with a massive 21.5-hectare campus in Sampaloc, Manila, which is a National Historical Landmark.', 'UST Angelicum (Quezon City)', 'Estimated Total per Semester: ₱50,000 – ₱75,000. Annual Total: approximately ₱100,000 – ₱150,000. Scholarships: San Martin de Porres (financial aid), Santo Tomas Academic (100% tuition for Highest Honors), San Lorenzo Ruiz (student assistant program), Santo Domingo (for talented athletes and artists).', 'Entrance Exam (USTET). Examination took place in August 8, 2025, to January 19, 2026. Fee: ₱600 for local students (waived for top honors or indigent families). Must be a Senior High School graduate or current Grade 12 student. Must pass the competitive USTET covering English, Math, Science, and Mental Ability.', 'Application Form fully accomplished via the official USTET online portal\nID Picture: Recent 2x2 colored photo with white background and name tag\nGrades Form: Digital or printed copy of encoded Grade 10 and 11 grades\nPSA Birth Certificate', 'Original Report Card (Form 138)\nOriginal PSA Birth Certificate\nGood Moral Certificate\nConfirmation of Enrollment Form\nMedical Clearance', 'Phone: +63-2-3406-1611 | +63-2-8786-1611\nEmail: inquiries@ust.edu.ph\nWebsite: https://www.ust.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(148, 'University of the East - Manila', 'Private', 'Manila', 'Founded in 1946 and quickly grew to become one of the most respected universities in the country. A private, non-sectarian school famous for its \"Warrior\" spirit. Focuses on making high-quality education accessible and practical. A top-tier choice for studying in a busy, high-energy environment right in the heart of Manila\'s University Belt.', 'UE Caloocan\nUERM Memorial Medical Center', 'Estimated Total per Semester: ₱45,000 – ₱65,000. Annual Total: approximately ₱90,000 – ₱130,000. UE-Tan Yan Kee Foundation scholarship for high-performing freshmen. Family Discount and Academic Excellence discounts available.', 'Entrance Exam (UE CET) ongoing. Regular testing happens weekly. Special FREE testing events occur in February and March 2026. Fee: Usually ₱400 – ₱600 (but waived during promo periods). Must be a graduate of a recognized secondary school. Must meet the specific grade requirements for \"Quota\" courses like Dentistry or Accountancy.', 'Accomplished Online Application Form\nOne (1) copy of your latest 2x2 ID photo (white background)\nGrade 12 Report Card (or Grade 11 card if currently in Grade 12)\nProof of payment of the application fee (unless waived)\nAfter acceptance:\nOriginal Form 138 (Grade 12 Report Card)\nOriginal Certificate of Good Moral Character\nOriginal PSA Birth Certificate\nFor Honors: Certification from Principal showing Rank and total number of graduates', 'Submit all original credentials to the Admissions Office\nDean\'s Interview\nNotice of Admission (NOA)\nPayment of initial downpayment at the Finance Department', 'Address: 2219 C.M. Recto Avenue, Brgy. 404, Zone 41, Sampaloc, Manila, Philippines\nTrunkline: Manila Campus (632) 8735-54-71 | 5328-5471\nAdmission Mobile: 0961-568-2179 (Smart)\nWebsite: https://www.ue.edu.ph/mla/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(149, 'STI College - Sta. Mesa', 'Private', 'Manila', 'Began as a computer training center in 1983 and has since grown into a massive network of academic centers. Famous for its Industry-Driven Curriculum, partnering with big companies like Microsoft and Huawei to ensure classroom learning matches real-world work. Offers modern, tech-heavy education with a clear path to employment after graduation.', 'STI College Caloocan\nSTI College Cubao\nSTI College Fairview\nSTI College Muñoz-EDSA\nSTI College Novaliches\nSTI College Alabang\nSTI College Las Piñas\nSTI College Makati\nSTI College Marikina\nSTI College Ortigas-Cainta\nSTI College Pasay-EDSA', 'Estimated Total per Semester: ₱30,000 – ₱45,000 depending on the course and campus location. STI Open Scholarship (SOS): Partial to full tuition grants based on a qualifying exam. GSIS/Pag-IBIG Benefit: 10% to 20% tuition subsidies. Honor Student Discount for high honors graduates.', 'STI Student Career Optimization Test (SCOT). Fee: Usually Free or included in the application fee (around ₱250 – ₱500 depending on the branch). Exams are ongoing year-round. Must be a Senior High School (SHS) graduate from a DepEd-recognized secondary school.', 'Original Form 138 / SF9-SHS (Learner\'s Progress Report Card)\nOriginal Form 137 / SF10-SHS (Learner\'s Permanent Academic Record)\nPSA-issued Birth Certificate\nOriginal Copy of Certificate of Good Moral Character\nMedical Certificate of Chest X-ray results', 'Document proving you passed the evaluation\nComplete Original Credentials\nPayment of Downpayment', 'Address: STI Academic Center, P. Sanchez Street corner Pat Antonio Street, Sta. Mesa, Manila, 1035\nTelephone: 8635-5954\nWebsite: https://www.sti.edu/campuses-details.asp?campus_id=U0hB', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(150, 'AMA Computer College - Sta. Mesa', 'Private', 'Manila', 'Founded in 1980, famous for being the first school in the country to offer a full degree in Computer Science. The Sta. Mesa branch is a dedicated tech hub focusing on \"Blended Learning\" – a mix of face-to-face classes and online study. Provides high-tech training with strong partnerships with global tech giants like Microsoft, Google, and Cisco.', 'AMACC Makati\nAMACC Caloocan\nAMACC Manila\nACLC College', 'AMA typically operates on a Trimester system (3 terms per year). Estimated Total per Term: ₱30,000 – ₱45,000. Annual Total: approximately ₱90,000 – ₱135,000. Full Cash Payment discount, DepEd Voucher accepted, Referral/Sibling Discount available.', 'All freshmen must take the AMA Computerized Knowledge and Cognitive System (CKCS) entrance exam. Must be a Senior High School graduate from a recognized school. Must meet the school\'s general admission standards (passing the exam and interview).', '1x1 and 2x2 ID Pictures (White background)\nOriginal Copy of Form 137 / Transcript of Records\nPhotocopy of PSA Birth Certificate\nCertificate of Good Moral Character\nAccomplished Application Form', 'Notice of Acceptance\nComplete Original Credentials: Surrendering your original SHS Report Card (Form 138)\nSigned Enrollment Forms\nInitial Payment: Downpayment or full tuition payment to secure your subjects', 'Address: 804-805 Cm Recto Avenue Cor Quezon Ave., Sampaloc Manila\nEmail: ama_stamesa@amaes.edu.ph\nPhone: 09625896613\nWebsite: https://www.amaes.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(151, 'FEU Institute of Technology', 'Private', 'Manila', 'Famous for its \"Technology Driven by Innovation\" approach. Established to provide high-end technical training through partnerships with global giants like IBM and Cisco. Unlike most schools that use semesters, FEU Tech uses a Trimester system (3 terms per year), allowing students to finish their degrees faster or take more focused specialized subjects.', 'FEU Alabang\nFEU Diliman', 'Per Term (Trimester): ₱50,000 – ₱58,000. Annual Total: approximately ₱150,000 – ₱174,000 (for 3 terms). Academic Scholarships: Full or partial tuition waivers for honor students. Family Discount: 15% discount for younger siblings. Flexible Payment through installment plans.', 'Applicants must take the FEU Tech Admission Test (specialized version of the FEUCAT). Special Exam Fee: approximately ₱500. Must be a Senior High School graduate or candidate for graduation from a recognized secondary school.', '1 latest 1x1 ID Picture and 1 latest 2x2 ID Picture (white background)\nOriginal or certified copy of Transcript of Records / Form 137\nPhotocopy of PSA Birth Certificate\nCertificate of Good Moral Character\nAccomplished Application Form via the FEU Tech portal\nFEUOCAT result\nAdmissions form\nSF9 / Grade 12 report card', 'Notice of Acceptance (provided by the Admissions Office)\nComplete Original Credentials (Report Card, Good Moral, etc.)\nSigned Enrollment Forms\nDown Payment: Payment of the initial tuition fee to validate enrollment', 'Email: admissions@feutech.edu.ph\nTrunkline: (02) 8281 8888 Local 123/131\nWebsite: https://www.feutech.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(152, 'Makati Science Technological Institute of the Philippines (MSTIP)', 'Private', 'Makati', 'A private, non-sectarian college that focuses on \"Practical Technology.\" Famous for offering flexible learning options and industry-aligned courses that prepare students for the modern workforce. Offers a straightforward, tech-heavy education in a professional Makati setting.', 'Main Campus: 4410 Singian St. (near Makati Ave.), Makati City', 'Estimated Total per Semester: ₱25,000 – ₱35,000. Full Payment: Usually 5% to 10% discount if paid in full. Sibling Discount and Academic Scholarship available.', 'CKCS Entrance Examination: All incoming freshmen are required to take the entrance exam. Brief interview with the Dean or Admissions Officer may be required. Must be a Senior High School graduate from a DepEd-recognized school.', '1x1 and 2x2 ID Pictures (White background)\nOriginal Copy of Transcript of Records / Form 137\nPhotocopy of PSA Birth Certificate\nCertificate of Good Moral Character\nAccomplished Application Form', 'Notice of Acceptance\nComplete Original Credentials (Surrendering your original Form 138/Report Card)\nSigned Enrollment Forms\nPayment of Downpayment to officially secure your subjects and section', 'Address: 4410 ERL BLDG. OLD STA. MESA, Manila, Philippines\nEmail: admission@mstip.edu.ph\nWebsite: mstip.edu.ph', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(153, 'Navotas Polytechnic College', 'LUC', 'Navotas', 'A public higher education institution established in 1994 under the City Government of Navotas. Main goal is to provide affordable and accessible education especially for residents of Navotas, helping students gain skills and contribute to local development.', 'NPC has only one main campus located in Navotas City.', '₱50 per unit (Navoteños) / ₱100 per unit (Non-Navoteños). Some fees may still apply (miscellaneous, lab, etc.). Full Scholarship Program available for qualified Navotas residents.', 'Must take the Navotas Polytechnic College Entrance Exam (NPCEE). Must be a Senior High School graduate or graduating student. Must meet basic academic and admission requirements. The college prioritizes local residents (Navoteños) in admissions and benefits. Being a registered voter of Navotas may be required for scholarship eligibility.', 'High School Report Card (Form 138 / 137)\nCertificate of Good Moral Character\nPSA Birth Certificate\n2 pieces Passport size ID pictures\nBarangay clearance / proof of residency\nAdditional forms from the school (if required)', 'Valid ID\nReport Card (Original + photocopy)\nCertificate of Good Moral Character\nPSA Birth Certificate\nPassport-size photos + 1x1 photo\nCedula (Residence Certificate)\nLong brown envelope', 'Address: Kapitbahayan Multi-Purpose Hall, North Bay Boulevard South Kaunlaran, Navotas City\nPhone: (028) 571 6323\nEmail: navotaspolytechniccollege94@gmail.com\nWebsite: https://navotaspolytechniccollege.edu.ph/', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(154, 'Governor Andres Pascual College', 'Private', 'Navotas', 'A private, non-sectarian college established in Navotas City, officially recognized in 1995. One of the first private colleges in Navotas offering higher education. Known for low tuition fees, making it accessible for many students.', 'The college has only one campus.', 'Around ₱5,000 – ₱7,000 per semester for undergraduate programs. Downpayment may be required (around ₱2,000). Payment can be cash or installment.', 'The school may require an entrance exam, especially for college applicants. Admission is generally based on academic records and basic screening or evaluation. Must be a Grade 12 student or high school graduate meeting basic academic requirements.', 'Grade 12 Report Card (Form 138)\nCertificate of Enrollment (if graduating)\nPSA Birth Certificate\n2x2 ID Picture\nValid ID or school ID\nAfter passing:\nOriginal Report Card / Transcript of Records\nCertificate of Good Moral Character\nAdditional school forms (provided during admission)', 'Report Card (Form 138)\nPSA Birth Certificate\nCertificate of Good Moral Character\n2x2 ID pictures\nCompleted application/enrollment form', 'Address: 1045 M. Naval Street, San Jose, Navotas City, 1485\nPhone: 282829036\nEmail: govapcollege@yahoo.com', '2026-05-09 16:40:23', '2026-05-09 16:40:23'),
(205, 'Metropolitan Medical Center College of Arts, Science and Technology', 'Private', 'Manila', 'MMC CAST is a private non-profit educational institution located in Sta. Cruz, Manila, Philippines. It was established in 1976 as the Metropolitan Hospital School of Nursing to support the nursing workforce needs of Metropolitan Medical Center. It later expanded into a full college and adopted its present name in 2009.', 'MMC CAST mainly operates as a single-campus institution integrated with Metropolitan Medical Center. ', 'Estimated private medical/allied health tuition may vary widely by program around ₱40,000 – ₱50,000 per year ', '', 'MMC CAST Examination\nTake the MMC CAST Cognitive and Analytical Test (MMCCAST-CAT). \nMinimum Qualifications\nMust be a Senior High School graduate (for freshmen)\nMust come from a recognized secondary school\nTransferees and second coursers may also apply\nRequired Documents\nAnswered online application\nPSA Birth Certificate (original)\nForm 138 / Grade 12 Report Card (for freshmen)\nTranscript of Records / Certificate of Grades (for transferees)\nHonorable Dismissal (for transferees/second coursers)\nCertificate of Good Moral Character\n2x2 ID pictures (2 copies)\nOne long brown envelope\nAdditional Documents\nOriginal academic credentials\nMedical examination / clearance (if required)\nProgram-specific requirements', 'Completion of requirements checked by Registrar\nTuition fee payment / assessment\nIssuance of registration forms', 'Address: 1357 G. Masangkay Street, Sta. Cruz, Manila 1008, Philippines (near Bambang Station LRT Line 1) \nPhone: (+63927) 7048319 or (+632) 8863-2500 or (+632) 8254-1111, Local 7153 \nEmail: info@metro.edu.ph \nWebsite: https://metro.edu.ph/', '2026-05-10 11:51:53', '2026-05-10 11:53:38');
